import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom'; // Adicionado useNavigate
import { useAuth } from '../../hooks/useAuth';

export function StudentHeader() {
  const { logout } = useAuth();
  const location = useLocation();
  const navigate = useNavigate(); // Hook para navegação via Select

  // Lógica de Ativação das Abas
  const isPlanos = location.pathname === '/app/dashboard' || location.pathname === '/app/calendar' || location.pathname.includes('/app/modules');
  const isSimulados = location.pathname.includes('/app/simulados');
  const isCursos = location.pathname.includes('/app/courses');

  // Define o valor atual do Select Mobile
  let currentSelectValue = '/app/dashboard';
  if (isSimulados) currentSelectValue = '/app/simulados';
  if (isCursos) currentSelectValue = '/app/courses';

  const handleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  return (
    <header className="h-16 w-full bg-black border-b border-gray-800 flex items-center justify-between px-3 md:px-6 sticky top-0 z-50">

      {/* --- ESQUERDA: LOGO --- */}
      <div className="flex items-center gap-2 w-auto md:w-48 shrink-0 transition-all">
         {/* No mobile reduzimos um pouco o texto para 18px (text-lg), no desktop 24px (text-2xl) */}
         <span className="text-lg md:text-2xl font-black text-white italic tracking-tighter truncate">
           INSANUS<span className="text-red-600">PLANNER</span>
         </span>
      </div>

      {/* --- CENTRO: NAVEGAÇÃO HÍBRIDA --- */}

      {/* 1. VERSÃO DESKTOP (Botões) - Oculto em Mobile (hidden md:flex) */}
      <div className="hidden md:flex items-center bg-[#121418] p-1 rounded-lg border border-gray-800">
          <Link 
              to="/app/dashboard"
              className={`flex items-center gap-2 px-6 py-2 rounded text-xs font-bold uppercase transition-all
                  ${isPlanos ? 'bg-red-600 text-white shadow-lg shadow-red-900/50' : 'text-gray-400 hover:text-white hover:bg-white/5'}
              `}
          >
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
              Planos
          </Link>

          <div className="w-px h-4 bg-gray-700 mx-1"></div>

          <Link 
              to="/app/simulados"
              className={`flex items-center gap-2 px-6 py-2 rounded text-xs font-bold uppercase transition-all
                  ${isSimulados ? 'bg-white text-black shadow-lg' : 'text-gray-400 hover:text-white hover:bg-white/5'}
              `}
          >
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" /></svg>
              Simulados
          </Link>

          <div className="w-px h-4 bg-gray-700 mx-1"></div>

          <Link 
              to="/app/courses"
              className={`flex items-center gap-2 px-6 py-2 rounded text-xs font-bold uppercase transition-all
                  ${isCursos ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/50' : 'text-gray-400 hover:text-white hover:bg-white/5'}
              `}
          >
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
              Cursos Online
          </Link>
      </div>

      {/* 2. VERSÃO MOBILE (Select Dropdown) - Visível apenas em Mobile (md:hidden) */}
      <div className="flex md:hidden flex-1 mx-3 max-w-[200px]">
        <div className="relative w-full">
            <select
                value={currentSelectValue}
                onChange={(e) => navigate(e.target.value)}
                className="w-full appearance-none bg-[#121418] border border-gray-800 text-white text-[10px] font-bold uppercase rounded-lg py-2 pl-3 pr-8 focus:border-red-600 outline-none transition-colors truncate"
            >
                <option value="/app/dashboard">📌 Planos</option>
                <option value="/app/simulados">🎓 Simulados</option>
                <option value="/app/courses">▶️ Cursos Online</option>
            </select>
            {/* Ícone de Seta customizado para o Select */}
            <div className="absolute inset-y-0 right-0 flex items-center px-2 pointer-events-none text-gray-500">
                <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>
            </div>
        </div>
      </div>

      {/* --- DIREITA: UTILITÁRIOS --- */}
      <div className="flex items-center justify-end gap-3 w-auto md:w-48 shrink-0">

          <button onClick={handleFullScreen} className="text-gray-500 hover:text-white transition-colors flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" /></svg>
              <span className="text-[10px] font-bold uppercase hidden md:inline">Tela Cheia</span>
          </button>

          <div className="h-4 w-px bg-gray-800 hidden md:block"></div>

          <button onClick={logout} className="text-gray-500 hover:text-red-500 transition-colors flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
              <span className="text-[10px] font-bold uppercase hidden md:inline">Sair</span>
          </button>
      </div>

    </header>
  );
}

