import React, { useState, useEffect, useRef } from 'react';
import { courseService } from '../../../../services/courseService';
// Importe a tipagem e o helper
import { ContestStatus, CONTEST_STATUS_LABELS } from '../../../../types/course';

interface CourseModalProps {
  isOpen: boolean;
  onClose: () => void;
  // Atualize a assinatura do onSave para receber os novos dados
  onSave: (data: { 
    title: string; 
    organization: string; 
    coverUrl: string; 
    description: string;
    contestStatus: ContestStatus; // Novo
    examBoard?: string;           // Novo
    examDate?: string;            // Novo
  }) => Promise<void>;
  initialData?: any;
}

export function CourseModal({ isOpen, onClose, onSave, initialData }: CourseModalProps) {
  const [title, setTitle] = useState('');
  const [organization, setOrganization] = useState('');
  const [description, setDescription] = useState('');
  const [coverUrl, setCoverUrl] = useState('');

  // --- NOVOS ESTADOS ---
  const [contestStatus, setContestStatus] = useState<ContestStatus>('SEM_PREVISAO');
  const [examBoard, setExamBoard] = useState('');
  const [examDate, setExamDate] = useState('');

  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [previewUrl, setPreviewUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      setTitle(initialData?.title || '');
      setOrganization(initialData?.organization || '');
      setDescription(initialData?.description || '');
      setCoverUrl(initialData?.coverUrl || '');
      setPreviewUrl(initialData?.coverUrl || '');

      // Carrega novos campos se existirem
      setContestStatus(initialData?.contestStatus || 'SEM_PREVISAO');
      setExamBoard(initialData?.examBoard || '');
      setExamDate(initialData?.examDate || '');

      setSelectedFile(null);
    }
  }, [isOpen, initialData]);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setSelectedFile(file);
      setPreviewUrl(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim()) return;
    setLoading(true);

    let finalUrl = coverUrl;
    if (selectedFile) {
        try {
            finalUrl = await courseService.uploadCover(selectedFile);
        } catch (error) {
            alert("Erro no upload da capa");
            setLoading(false);
            return;
        }
    }

    // Envia objeto completo
    await onSave({
        title,
        organization,
        description,
        coverUrl: finalUrl,
        contestStatus,
        examBoard: contestStatus === 'BANCA_CONTRATADA' ? examBoard : undefined, // Limpa se mudou status
        examDate: contestStatus === 'EDITAL_PUBLICADO' ? examDate : undefined     // Limpa se mudou status
    });

    setLoading(false);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in">
      <div className="bg-[#121418] border border-gray-800 rounded-xl w-full max-w-2xl shadow-2xl max-h-[90vh] overflow-y-auto custom-scrollbar">
        <div className="p-4 border-b border-gray-800 flex justify-between items-center sticky top-0 bg-[#121418] z-10">
          <h3 className="text-white font-bold">{initialData ? 'Editar Curso' : 'Novo Curso'}</h3>
          <button onClick={onClose} className="text-gray-400 hover:text-white">✕</button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5">

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Título */}
            <div className="md:col-span-2">
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Nome do Curso</label>
                <input 
                type="text" 
                value={title}
                onChange={e => setTitle(e.target.value)}
                className="w-full bg-black border border-gray-800 rounded p-3 text-white focus:border-red-600 outline-none"
                required
                placeholder="Ex: Polícia Civil SP - Agente"
                />
            </div>

            {/* Organização */}
            <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Organização / Cargo</label>
                <input 
                type="text" 
                value={organization}
                onChange={e => setOrganization(e.target.value)}
                className="w-full bg-black border border-gray-800 rounded p-3 text-white focus:border-red-600 outline-none"
                placeholder="Ex: PC-SP"
                />
            </div>

            {/* STATUS DO CONCURSO (NOVO) */}
            <div>
                <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Status do Concurso</label>
                <select 
                    value={contestStatus}
                    onChange={e => setContestStatus(e.target.value as ContestStatus)}
                    className="w-full bg-black border border-gray-800 rounded p-3 text-white focus:border-red-600 outline-none"
                >
                    {Object.entries(CONTEST_STATUS_LABELS).map(([key, label]) => (
                        <option key={key} value={key}>{label}</option>
                    ))}
                </select>
            </div>
          </div>

          {/* CAMPOS CONDICIONAIS */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-[#1a1d24] p-4 rounded-lg border border-gray-800">

             {/* Condicional: Banca Contratada */}
             {contestStatus === 'BANCA_CONTRATADA' && (
                <div className="md:col-span-2 animate-in slide-in-from-top-2">
                    <label className="block text-xs font-bold text-yellow-500 uppercase mb-1">Nome da Banca Examinadora</label>
                    <input 
                        type="text" 
                        value={examBoard}
                        onChange={e => setExamBoard(e.target.value)}
                        className="w-full bg-black border border-gray-700 rounded p-3 text-white focus:border-yellow-500 outline-none"
                        placeholder="Ex: CEBRASPE, FGV, VUNESP..."
                        autoFocus
                    />
                </div>
             )}

             {/* Condicional: Edital Publicado */}
             {contestStatus === 'EDITAL_PUBLICADO' && (
                <div className="md:col-span-2 animate-in slide-in-from-top-2">
                    <label className="block text-xs font-bold text-red-500 uppercase mb-1">Data da Prova (Para o Contador)</label>
                    <input 
                        type="date" 
                        value={examDate}
                        onChange={e => setExamDate(e.target.value)}
                        className="w-full bg-black border border-gray-700 rounded p-3 text-white focus:border-red-500 outline-none"
                        autoFocus
                    />
                    <p className="text-[10px] text-gray-500 mt-1">Isso ativará o contador regressivo na área do aluno.</p>
                </div>
             )}

             {/* Outros status apenas informativos */}
             {['SEM_PREVISAO', 'COMISSAO_FORMADA', 'AUTORIZADO'].includes(contestStatus) && (
                 <div className="md:col-span-2 text-center text-gray-500 text-xs italic">
                    O status "{CONTEST_STATUS_LABELS[contestStatus]}" será exibido como um aviso simples para o aluno.
                 </div>
             )}
          </div>

          {/* Descrição */}
          <div>
            <label className="block text-xs font-bold text-gray-400 uppercase mb-1">Descrição</label>
            <textarea 
              value={description}
              onChange={e => setDescription(e.target.value)}
              className="w-full bg-black border border-gray-800 rounded p-3 text-white focus:border-red-600 outline-none h-24 resize-none"
            />
          </div>

          {/* Upload Capa */}
          {/* ... (código de upload de capa mantém igual) ... */}
          <div 
                onClick={() => fileInputRef.current?.click()}
                className={`
                    relative w-full aspect-video rounded-lg border-2 border-dashed 
                    flex flex-col items-center justify-center cursor-pointer overflow-hidden group
                    ${previewUrl ? 'border-red-600/50' : 'border-gray-700 hover:border-gray-500 hover:bg-white/5'}
                `}
            >
                <input type="file" ref={fileInputRef} onChange={handleFileSelect} accept="image/*" className="hidden" />
                {previewUrl ? (
                    <img src={previewUrl} alt="Capa" className="w-full h-full object-cover opacity-60 group-hover:opacity-40 transition-opacity" />
                ) : (
                    <div className="text-center p-4">
                        <span className="text-gray-400 text-xs font-bold">CAPA DO CURSO</span>
                    </div>
                )}
            </div>

          <div className="flex justify-end gap-2 pt-4 border-t border-gray-800">
            <button type="button" onClick={onClose} className="px-4 py-2 text-gray-400 hover:text-white font-bold text-xs uppercase">Cancelar</button>
            <button type="submit" disabled={loading} className="px-6 py-2 bg-red-600 hover:bg-red-500 text-white font-bold text-xs uppercase rounded">
              {loading ? 'Salvando...' : 'Salvar'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

