         // Ao mover, idealmente recalcular a ordem, mas para simplificar, mantém a atual ou joga pro fim
     });
  },

  // NOVA FUNÇÃO: Reordenar Aulas
  reorderLessons: async (lessons: CourseLesson[]) => {
