import React, { useState, useEffect } from 'react';
import { Save, Plus, Loader2, FileText, ToggleLeft, ToggleRight } from 'lucide-react';
import { CourseEditalStructure, CourseEditalDiscipline } from '../../../../../types/courseEdital';
import { courseService } from '../../../../../services/courseService';
import { AdminCourseEditalDiscipline } from './AdminCourseEditalDiscipline';

interface AdminCourseEditalManagerProps {
  courseId: string;
}

// Helper ID
const generateId = () => Math.random().toString(36).substr(2, 9);

export function AdminCourseEditalManager({ courseId }: AdminCourseEditalManagerProps) {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [editalData, setEditalData] = useState<CourseEditalStructure>({
    courseId,
    status: 'PRE_EDITAL',
    disciplines: [],
    updatedAt: null
  });

  const [newDisciplineName, setNewDisciplineName] = useState('');

  // Carregar Dados
  useEffect(() => {
    const load = async () => {
        setLoading(true);
        const data = await courseService.getCourseEdital(courseId);
        if (data) {
            setEditalData(data);
        }
        setLoading(false);
    };
    load();
  }, [courseId]);

  // Salvar Dados
  const handleSave = async () => {
    setSaving(true);
    try {
        await courseService.saveCourseEdital(editalData);
    } catch (error) {
        console.error("Erro ao salvar edital:", error);
        alert("Erro ao salvar.");
    } finally {
        setSaving(false);
    }
  };

  // Handlers
  const toggleStatus = () => {
    setEditalData(prev => ({
        ...prev,
        status: prev.status === 'PRE_EDITAL' ? 'POS_EDITAL' : 'PRE_EDITAL'
    }));
  };

  const handleAddDiscipline = () => {
    if (!newDisciplineName.trim()) return;
    const newDiscipline: CourseEditalDiscipline = {
        id: generateId(),
        name: newDisciplineName,
        topics: []
    };
    setEditalData(prev => ({
        ...prev,
        disciplines: [...prev.disciplines, newDiscipline]
    }));
    setNewDisciplineName('');
  };

  const handleUpdateDiscipline = (updatedDisc: CourseEditalDiscipline) => {
    setEditalData(prev => ({
        ...prev,
        disciplines: prev.disciplines.map(d => d.id === updatedDisc.id ? updatedDisc : d)
    }));
  };

  const handleDeleteDiscipline = (id: string) => {
    if (!confirm("Tem certeza que deseja excluir esta disciplina e todos os seus tópicos?")) return;
    setEditalData(prev => ({
        ...prev,
        disciplines: prev.disciplines.filter(d => d.id !== id)
    }));
  };

  if (loading) return <div className="p-8 text-center text-zinc-500 animate-pulse">Carregando Edital...</div>;

  return (
    <div className="bg-[#0f1115] border border-zinc-800 rounded-xl overflow-hidden flex flex-col h-full">

        {/* Header */}
        <div className="p-6 border-b border-zinc-800 bg-[#121418] flex items-center justify-between">
            <div>
                <h2 className="text-xl font-black text-white uppercase tracking-tighter flex items-center gap-2">
                    <FileText size={24} className="text-red-600" />
                    Edital Verticalizado
                </h2>
                <p className="text-zinc-500 text-xs mt-1">Organize o conteúdo programático e vincule às aulas.</p>
            </div>

            <div className="flex items-center gap-4">
                {/* Status Toggle */}
                <div 
                    onClick={toggleStatus}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg cursor-pointer border transition-colors ${editalData.status === 'POS_EDITAL' ? 'bg-red-900/20 border-red-500/50' : 'bg-zinc-800 border-zinc-700'}`}
                >
                    <span className={`text-xs font-bold uppercase ${editalData.status === 'POS_EDITAL' ? 'text-red-500' : 'text-zinc-400'}`}>
                        {editalData.status === 'POS_EDITAL' ? 'Pós-Edital' : 'Pré-Edital'}
                    </span>
                    {editalData.status === 'POS_EDITAL' ? <ToggleRight size={24} className="text-red-500"/> : <ToggleLeft size={24} className="text-zinc-500"/>}
                </div>

                <button 
                    onClick={handleSave}
                    disabled={saving}
                    className="flex items-center gap-2 px-6 py-2 bg-white hover:bg-zinc-200 text-black font-bold text-xs uppercase rounded transition-colors disabled:opacity-50"
                >
                    {saving ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                    Salvar Alterações
                </button>
            </div>
        </div>

        {/* Content */}
        <div className="p-6 flex-1 overflow-y-auto custom-scrollbar bg-black/20">

            {/* Adicionar Disciplina */}
            <div className="flex gap-2 mb-6 max-w-2xl">
                <input 
                    value={newDisciplineName}
                    onChange={(e) => setNewDisciplineName(e.target.value)}
                    placeholder="Nova Disciplina (Ex: Direito Constitucional)"
                    className="flex-1 bg-zinc-900 border border-zinc-700 rounded-lg px-4 py-3 text-white focus:border-red-600 focus:outline-none uppercase font-bold text-sm"
                    onKeyDown={(e) => e.key === 'Enter' && handleAddDiscipline()}
                />
                <button 
                    onClick={handleAddDiscipline}
                    disabled={!newDisciplineName.trim()}
                    className="bg-red-600 hover:bg-red-500 text-white px-6 rounded-lg font-bold uppercase text-xs disabled:opacity-50"
                >
                    + Adicionar
                </button>
            </div>

            {/* Lista de Disciplinas */}
            <div className="space-y-4">
                {editalData.disciplines.length === 0 && (
                    <div className="text-center py-20 border-2 border-dashed border-zinc-800 rounded-xl">
                        <p className="text-zinc-600 font-bold uppercase text-sm">Nenhuma disciplina cadastrada.</p>
                        <p className="text-zinc-700 text-xs mt-1">Comece adicionando uma matéria acima.</p>
                    </div>
                )}

                {editalData.disciplines.map(disc => (
                    <AdminCourseEditalDiscipline 
                        key={disc.id}
                        discipline={disc}
                        onUpdate={handleUpdateDiscipline}
                        onDelete={() => handleDeleteDiscipline(disc.id)}
                    />
                ))}
            </div>
        </div>
    </div>
  );
}

