import React, { useState, useEffect } from 'react';
import { OnlineCourse, CourseModule } from '../../../types/course';
import { courseService } from '../../../services/courseService';
import { CourseModuleCard } from './modules/CourseModuleCard';
import { CourseModuleModal } from './modules/CourseModuleModal';
import { ModuleContentManager } from './modules/ModuleContentManager';
import { ConfirmationModal } from '../ui/ConfirmationModal';
import { AdminCourseEditalManager } from './edital/AdminCourseEditalManager'; // Importando o Gerenciador de Edital
import { Layout, FileText } from 'lucide-react';

interface CourseContentManagerProps {
  course: OnlineCourse;
  onBack: () => void;
}

export function CourseContentManager({ course, onBack }: CourseContentManagerProps) {
  const [activeTab, setActiveTab] = useState<'MODULES' | 'EDITAL'>('MODULES');

  // --- ESTADOS DE MÓDULOS ---
  const [modules, setModules] = useState<CourseModule[]>([]);
  const [loading, setLoading] = useState(true);

  const [isModuleModalOpen, setIsModuleModalOpen] = useState(false);
  const [editingModule, setEditingModule] = useState<CourseModule | null>(null);
  const [moduleToDelete, setModuleToDelete] = useState<CourseModule | null>(null);
  const [managingModule, setManagingModule] = useState<CourseModule | null>(null);

  // Carregar Módulos
  const loadModules = async () => {
    setLoading(true);
    try {
      const data = await courseService.getModules(course.id);
      setModules(data);
    } catch (error) {
      console.error("Erro ao carregar módulos:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'MODULES') {
        loadModules();
    }
  }, [course.id, activeTab]);

  // CRUD Módulos
  const handleSaveModule = async (data: Partial<CourseModule>) => {
    if (editingModule) {
      await courseService.updateModule(editingModule.id, data);
    } else {
      await courseService.createModule({
        ...data,
        courseId: course.id,
        order: 999 
      } as any);
    }
    await loadModules();
    setEditingModule(null);
  };

  const handleDeleteModule = async () => {
    if (moduleToDelete) {
      await courseService.deleteModule(moduleToDelete.id);
      await loadModules();
      setModuleToDelete(null);
    }
  };

  const handleReorder = async (index: number, direction: 'left' | 'right') => {
    const newModules = [...modules];
    const targetIndex = direction === 'left' ? index - 1 : index + 1;
    [newModules[index], newModules[targetIndex]] = [newModules[targetIndex], newModules[index]];
    setModules(newModules);
    await courseService.reorderModules(newModules);
  };

  const handleManageInternal = (module: CourseModule) => {
    setManagingModule(module);
  };

  if (managingModule) {
    return (
      <ModuleContentManager 
        module={managingModule} 
        onBack={() => setManagingModule(null)} 
      />
    );
  }

  return (
    <div className="space-y-6 animate-in fade-in h-full flex flex-col">

      {/* Header com Navegação */}
      <div className="flex flex-col gap-4 border-b border-gray-800 pb-4 shrink-0">
          <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 hover:bg-white/5 rounded-full transition-colors text-gray-400 hover:text-white">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
            </button>
            <div>
            <span className="text-red-500 font-bold text-xs uppercase tracking-wider">Gerenciando Curso</span>
            <h2 className="text-2xl font-black text-white uppercase">{course.title}</h2>
            </div>
          </div>

          {/* Abas de Navegação */}
          <div className="flex gap-1 bg-zinc-900/50 p-1 rounded-lg border border-zinc-800 w-fit">
              <button 
                  onClick={() => setActiveTab('MODULES')}
                  className={`px-4 py-2 rounded-md text-xs font-bold uppercase flex items-center gap-2 transition-all ${activeTab === 'MODULES' ? 'bg-zinc-800 text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-300'}`}
              >
                  <Layout size={14} /> Módulos e Aulas
              </button>
              <button 
                  onClick={() => setActiveTab('EDITAL')}
                  className={`px-4 py-2 rounded-md text-xs font-bold uppercase flex items-center gap-2 transition-all ${activeTab === 'EDITAL' ? 'bg-zinc-800 text-white shadow-sm' : 'text-zinc-500 hover:text-zinc-300'}`}
              >
                  <FileText size={14} /> Edital Verticalizado
              </button>
          </div>
      </div>

      {/* Conteúdo da Aba */}
      <div className="flex-1 overflow-hidden">
          {activeTab === 'EDITAL' ? (
              <AdminCourseEditalManager courseId={course.id} />
          ) : (
             <div className="space-y-6 h-full overflow-y-auto custom-scrollbar p-1">
                <div className="flex justify-end">
                    <button 
                    onClick={() => { setEditingModule(null); setIsModuleModalOpen(true); }}
                    className="px-6 py-2 bg-red-600 hover:bg-red-500 text-white font-bold uppercase text-xs rounded shadow-lg shadow-red-900/20 flex items-center gap-2"
                    >
                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                    Novo Módulo
                    </button>
                </div>

                {loading ? (
                <div className="flex justify-center py-20"><div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-red-600"></div></div>
                ) : modules.length === 0 ? (
                <div className="text-center py-20 border border-dashed border-gray-800 rounded-xl">
                    <p className="text-gray-500">Nenhum módulo cadastrado neste curso.</p>
                </div>
                ) : (
                <div className="flex gap-6 overflow-x-auto pb-6 scrollbar-thin scrollbar-thumb-red-900 scrollbar-track-transparent px-1">
                    {modules.map((module, index) => (
                    <CourseModuleCard 
                        key={module.id}
                        module={module}
                        onEdit={(m) => { setEditingModule(m); setIsModuleModalOpen(true); }}
                        onDelete={setModuleToDelete}
                        onMoveLeft={() => { handleReorder(index, 'left'); }}
                        onMoveRight={() => { handleReorder(index, 'right'); }}
                        onManageContent={handleManageInternal}
                        isFirst={index === 0}
                        isLast={index === modules.length - 1}
                    />
                    ))}
                </div>
                )}
             </div>
          )}
      </div>

      {/* Modais (Apenas para Módulos) */}
      <CourseModuleModal 
        isOpen={isModuleModalOpen}
        onClose={() => setIsModuleModalOpen(false)}
        onSave={handleSaveModule}
        initialData={editingModule}
      />

      <ConfirmationModal 
        isOpen={!!moduleToDelete}
        title="Excluir Módulo?"
        message={`Deseja excluir "${moduleToDelete?.title}"? Todo o conteúdo interno será perdido.`}
        onConfirm={handleDeleteModule}
        onCancel={() => setModuleToDelete(null)}
        isDanger
      />
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { CourseEditalStructure, CourseEditalDiscipline } from '../../../../../types/courseEdital';
import { courseService } from '../../../../../services/courseService';
import { AdminCourseEditalDiscipline } from './AdminCourseEditalDiscipline';
import { Loader2 } from 'lucide-react';

interface EditalManagerProps {
    courseId: string;
}

// Helper para gerar ID
const generateId = () => Math.random().toString(36).substr(2, 9);

export const AdminCourseEditalManager: React.FC<EditalManagerProps> = ({ courseId }) => {
    const [editalStatus, setEditalStatus] = useState<'PRE_EDITAL' | 'POS_EDITAL'>('PRE_EDITAL');
    const [disciplines, setDisciplines] = useState<CourseEditalDiscipline[]>([]);
    const [loading, setLoading] = useState(true);

    // 1. Carregar dados do Edital
    useEffect(() => {
        const fetchEdital = async () => {
            setLoading(true);
            try {
                const data = await courseService.getCourseEdital(courseId);
                if (data) {
                    setEditalStatus(data.status);
                    setDisciplines(data.disciplines);
                } else {
                    // Inicializa se não existir
                    setEditalStatus('PRE_EDITAL');
                    setDisciplines([]);
                }
            } catch (error) {
                console.error("Erro ao carregar edital", error);
            } finally {
                setLoading(false);
            }
        };
        fetchEdital();
    }, [courseId]);

    // Função para Salvar Tudo (Status + Disciplinas)
    const saveAll = async (newStatus: 'PRE_EDITAL' | 'POS_EDITAL', newDisciplines: CourseEditalDiscipline[]) => {
        try {
            const structure: CourseEditalStructure = {
                courseId,
                status: newStatus,
                disciplines: newDisciplines,
                updatedAt: new Date()
            };
            await courseService.saveCourseEdital(structure);
        } catch (error) {
            console.error("Erro ao salvar edital", error);
        }
    };

    // 2. Handler de Status
    const handleStatusChange = async (newStatus: 'PRE_EDITAL' | 'POS_EDITAL') => {
        setEditalStatus(newStatus);
        await saveAll(newStatus, disciplines);
    };

    // 3. Adicionar Nova Disciplina
    const handleAddDiscipline = async () => {
        const newDiscipline: CourseEditalDiscipline = {
            id: generateId(),
            name: 'Nova Disciplina',
            topics: []
        };

        const updatedDisciplines = [...disciplines, newDiscipline];
        setDisciplines(updatedDisciplines);
        await saveAll(editalStatus, updatedDisciplines);
    };

    // 4. Callback para Atualização de Disciplinas (Passado para filhos)
    const handleDisciplineUpdate = async (updatedDiscipline: CourseEditalDiscipline) => {
        const updatedList = disciplines.map(d => d.id === updatedDiscipline.id ? updatedDiscipline : d);
        setDisciplines(updatedList);
        await saveAll(editalStatus, updatedList);
    };

    const handleDisciplineDelete = async (disciplineId: string) => {
        if (!confirm("Excluir disciplina e todos os tópicos?")) return;
        const updatedList = disciplines.filter(d => d.id !== disciplineId);
        setDisciplines(updatedList);
        await saveAll(editalStatus, updatedList);
    };

    if (loading) return <div className="flex justify-center p-10"><Loader2 className="animate-spin text-red-600" /></div>;

    return (
        <div className="space-y-6 w-full max-w-5xl mx-auto p-4 animate-in fade-in">
            {/* CABEÇALHO E STATUS DO EDITAL */}
            <div className="bg-[#1a1d24] p-6 rounded-xl border border-gray-800 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h2 className="text-2xl font-black text-white uppercase tracking-wider">Edital Verticalizado</h2>
                    <p className="text-gray-400 text-sm mt-1">Estruture os tópicos e vincule aulas, materiais e revisões.</p>
                </div>

                {/* CONTROLE DE STATUS (PRÉ/PÓS EDITAL) */}
                <div className="flex bg-black p-1 rounded-lg border border-gray-800">
                    <button
                        onClick={() => handleStatusChange('PRE_EDITAL')}
                        className={`px-6 py-2 rounded-md font-bold text-xs uppercase tracking-wider transition-all ${
                            editalStatus === 'PRE_EDITAL' 
                            ? 'bg-yellow-500 text-black shadow-lg' 
                            : 'text-gray-500 hover:text-white'
                        }`}
                    >
                        Pré-Edital
                    </button>
                    <button
                        onClick={() => handleStatusChange('POS_EDITAL')}
                        className={`px-6 py-2 rounded-md font-bold text-xs uppercase tracking-wider transition-all ${
                            editalStatus === 'POS_EDITAL' 
                            ? 'bg-red-600 text-white shadow-lg' 
                            : 'text-gray-500 hover:text-white'
                        }`}
                    >
                        Pós-Edital
                    </button>
                </div>
            </div>

            {/* LISTA DE DISCIPLINAS */}
            <div className="space-y-4">
                {disciplines.length === 0 && (
                    <div className="text-center py-10 border-2 border-dashed border-gray-800 rounded-xl text-gray-500">
                        Nenhuma disciplina criada.
                    </div>
                )}

                {disciplines.map((discipline) => (
                    <AdminCourseEditalDiscipline 
                        key={discipline.id} 
                        discipline={discipline} 
                        onUpdate={handleDisciplineUpdate}
                        onDelete={() => handleDisciplineDelete(discipline.id)}
                    />
                ))}
            </div>

            {/* BOTÃO ADICIONAR DISCIPLINA */}
            <button 
                onClick={handleAddDiscipline}
                className="w-full py-4 bg-transparent border-2 border-dashed border-gray-700 hover:border-yellow-500 text-gray-500 hover:text-yellow-500 rounded-xl font-bold uppercase tracking-widest transition-all flex items-center justify-center gap-2"
            >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
                </svg>
                Adicionar Disciplina
            </button>
        </div>
    );
};

import React, { useState } from 'react';
import { ChevronDown, ChevronRight, Plus, Trash2, BookOpen } from 'lucide-react';
import { CourseEditalDiscipline, CourseEditalTopic } from '../../../../../types/courseEdital';
import { AdminCourseEditalTopic } from './AdminCourseEditalTopic';

interface Props {
  discipline: CourseEditalDiscipline;
  onUpdate: (updated: CourseEditalDiscipline) => void;
  onDelete: () => void;
}

const generateId = () => Math.random().toString(36).substr(2, 9);

export const AdminCourseEditalDiscipline: React.FC<Props> = ({ discipline, onUpdate, onDelete }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isEditingName, setIsEditingName] = useState(false);
  const [localName, setLocalName] = useState(discipline.name);

  // Handlers
  const handleNameBlur = () => {
    setIsEditingName(false);
    if (localName !== discipline.name) {
        onUpdate({ ...discipline, name: localName });
    }
  };

  const handleAddTopic = (e: React.MouseEvent) => {
    e.stopPropagation();
    const newTopic: CourseEditalTopic = {
        id: generateId(),
        name: 'Novo Tópico',
        subtopics: [],
        links: { lessonIds: [], pdfIds: [], mindMapIds: [], flashcardIds: [] }
    };
    onUpdate({
        ...discipline,
        topics: [...discipline.topics, newTopic]
    });
    setIsOpen(true);
  };

  const handleTopicUpdate = (updatedTopic: CourseEditalTopic) => {
    onUpdate({
        ...discipline,
        topics: discipline.topics.map(t => t.id === updatedTopic.id ? updatedTopic : t)
    });
  };

  const handleTopicDelete = (topicId: string) => {
    onUpdate({
        ...discipline,
        topics: discipline.topics.filter(t => t.id !== topicId)
    });
  };

  return (
    <div className="border border-zinc-800 rounded-lg overflow-hidden bg-[#15171b]">
      {/* Header */}
      <div 
        className="flex items-center justify-between p-4 bg-[#1a1d24] hover:bg-[#202329] transition-colors cursor-pointer group" 
        onClick={() => setIsOpen(!isOpen)}
      >
        <div className="flex items-center gap-3 flex-1">
            <div className={`text-zinc-500 transition-transform duration-200 ${isOpen ? 'rotate-90' : ''}`}>
                <ChevronRight size={18} />
            </div>
            <BookOpen size={18} className="text-yellow-600" />

            {isEditingName ? (
                <input 
                    value={localName}
                    onChange={(e) => setLocalName(e.target.value)}
                    onBlur={handleNameBlur}
                    onClick={(e) => e.stopPropagation()}
                    autoFocus
                    className="bg-black border border-zinc-700 rounded px-2 py-1 text-white text-sm font-bold uppercase w-64 focus:outline-none focus:border-yellow-500"
                />
            ) : (
                <span 
                    className="text-white font-bold uppercase text-sm hover:text-yellow-500 transition-colors"
                    onClick={(e) => { e.stopPropagation(); setIsEditingName(true); }}
                    title="Clique para editar"
                >
                    {discipline.name}
                </span>
            )}

            <span className="text-xs text-zinc-600 font-mono bg-black/30 px-2 py-0.5 rounded border border-zinc-800 ml-2">
                {discipline.topics.length} Tópicos
            </span>
        </div>

        <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
            <button 
                onClick={handleAddTopic}
                className="px-3 py-1.5 bg-zinc-800 hover:bg-zinc-700 text-white rounded text-xs font-bold flex items-center gap-1 border border-zinc-700 uppercase"
            >
                <Plus size={12} /> Tópico
            </button>
            <button 
                onClick={(e) => { e.stopPropagation(); onDelete(); }}
                className="p-1.5 text-zinc-500 hover:text-red-500 hover:bg-red-500/10 rounded transition-colors"
                title="Excluir Disciplina"
            >
                <Trash2 size={16} />
            </button>
        </div>
      </div>

      {/* Body */}
      {isOpen && (
        <div className="bg-black/30 p-2 pl-4 border-t border-zinc-800 space-y-2">
            {discipline.topics.length === 0 ? (
                <div className="text-center py-6 text-zinc-600 text-xs italic">Nenhum tópico cadastrado. Adicione um acima.</div>
            ) : (
                discipline.topics.map(topic => (
                    <AdminCourseEditalTopic 
                        key={topic.id}
                        topic={topic}
                        onUpdate={handleTopicUpdate}
                        onDelete={() => handleTopicDelete(topic.id)}
                    />
                ))
            )}
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
