interface Props {
  discipline: CourseEditalDiscipline;
  onUpdate: (updated: CourseEditalDiscipline) => void;
  onDelete: () => void;
}

const generateId = () => Math.random().toString(36).substr(2, 9);

export const AdminCourseEditalDiscipline: React.FC<Props> = ({ discipline, onUpdate, onDelete }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isEditingName, setIsEditingName] = useState(false);
  const [localName, setLocalName] = useState(discipline.name);

  // Handlers
  const handleNameBlur = () => {
    setIsEditingName(false);
    if (localName !== discipline.name) {
        onUpdate({ ...discipline, name: localName });
    }
  };

  const handleAddTopic = (e: React.MouseEvent) => {
    e.stopPropagation();
    const newTopic: CourseEditalTopic = {
        id: generateId(),
        name: 'Novo Tópico',
        subtopics: [],
        links: { lessonIds: [], pdfIds: [] },
        contentData: { mindMap: [], flashcards: [] }
    };
    onUpdate({
        ...discipline,
        topics: [...discipline.topics, newTopic]
    });
    setIsOpen(true);
  };

  const handleTopicUpdate = (updatedTopic: CourseEditalTopic) => {
    onUpdate({
        ...discipline,
        topics: discipline.topics.map(t => t.id === updatedTopic.id ? updatedTopic : t)
    });
  };

  const handleTopicDelete = (topicId: string) => {
    if(!confirm('Excluir este tópico e todo seu conteúdo?')) return;
    onUpdate({
        ...discipline,
        topics: discipline.topics.filter(t => t.id !== topicId)
    });
  };

  return (
    <div className="border border-zinc-800 rounded-lg overflow-hidden bg-[#15171b] mb-3 transition-all hover:border-zinc-700">
      {/* Header */}
      <div 
        className="flex items-center justify-between p-4 bg-[#1a1d24] hover:bg-[#202329] transition-colors cursor-pointer group select-none" 
        onClick={() => setIsOpen(!isOpen)}
      >
        <div className="flex items-center gap-3 flex-1">
            <div className={`text-zinc-500 transition-transform duration-200 ${isOpen ? 'rotate-90' : ''}`}>
                <ChevronRight size={18} />
            </div>
            <BookOpen size={18} className="text-red-600" />

            {isEditingName ? (
                <input 
                    value={localName}
                    onChange={(e) => setLocalName(e.target.value)}
                    onBlur={handleNameBlur}
                    onClick={(e) => e.stopPropagation()}
                    autoFocus
                    className="bg-black border border-zinc-700 rounded px-2 py-1 text-white text-sm font-bold uppercase w-64 focus:outline-none focus:border-red-500"
                />
            ) : (
                <span 
                    className="text-white font-bold uppercase text-sm hover:text-red-400 transition-colors"
                    onClick={(e) => { e.stopPropagation(); setIsEditingName(true); }}
                    title="Clique para editar"
                >
                    {discipline.name}
                </span>
            )}

            <span className="text-xs text-zinc-600 font-mono bg-black/30 px-2 py-0.5 rounded border border-zinc-800 ml-2">
                {discipline.topics.length} Tópicos
            </span>
        </div>

        <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
            <button 
                onClick={handleAddTopic}
                className="px-3 py-1.5 bg-zinc-800 hover:bg-zinc-700 text-white rounded text-xs font-bold flex items-center gap-1 border border-zinc-700 uppercase"
            >
                <Plus size={12} /> Tópico
            </button>
            <button 
                onClick={(e) => { e.stopPropagation(); onDelete(); }}
                className="p-1.5 text-zinc-500 hover:text-red-500 hover:bg-red-500/10 rounded transition-colors"
                title="Excluir Disciplina"
            >
                <Trash2 size={16} />
            </button>
        </div>
      </div>

      {/* Body */}
      {isOpen && (
        <div className="bg-black/20 p-2 pl-4 border-t border-zinc-800 space-y-2">
            {discipline.topics.length === 0 ? (
                <div className="text-center py-6 text-zinc-600 text-xs italic">Nenhum tópico cadastrado. Adicione um acima.</div>
            ) : (
                discipline.topics.map(topic => (
                    <AdminCourseEditalTopic 
                        key={topic.id}
                        topic={topic}
                        onUpdate={handleTopicUpdate}
                        onDelete={() => handleTopicDelete(topic.id)}
                    />
                ))
            )}
        </div>
      )}
    </div>
  );
};

