                    className="text-zinc-300 hover:text-white text-xs font-medium cursor-text transition-colors truncate"
                >
                    {topic.name}
                </span>

                {/* Badges de Conteúdo */}
                {lessonsCount > 0 && <span className="text-[9px] bg-blue-500/20 text-blue-400 px-1 rounded border border-blue-500/30 flex items-center gap-0.5"><PlayCircle size={8}/> {lessonsCount}</span>}
                {pdfsCount > 0 && <span className="text-[9px] bg-orange-500/20 text-orange-400 px-1 rounded border border-orange-500/30 flex items-center gap-0.5"><FileText size={8}/> {pdfsCount}</span>}
                {mapCount > 0 && <span className="text-[9px] bg-purple-500/20 text-purple-400 px-1 rounded border border-purple-500/30 flex items-center gap-0.5"><BrainCircuit size={8}/> Mapa</span>}
                {flashCount > 0 && <span className="text-[9px] bg-pink-500/20 text-pink-400 px-1 rounded border border-pink-500/30 flex items-center gap-0.5"><Layers size={8}/> Cards</span>}
              </div>
          )}
        </div>

        {/* Action Buttons (Visible on Hover) */}
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">

