                <button onClick={handleUploadPDFClick} disabled={isUploading} className="p-1.5 text-orange-500 hover:bg-orange-900/30 hover:text-orange-400 disabled:opacity-50" title="Upload PDF Material">
                    {isUploading ? <span className="animate-spin text-[8px]">↻</span> : <FileText size={12} />}
