                <div className="w-px bg-zinc-800"></div>
                <button onClick={() => setActiveTool('MAP')} className="p-1.5 text-purple-500 hover:bg-purple-900/30 hover:text-purple-400" title="Gerar Mapa Mental (IA)"><BrainCircuit size={12} /></button>
