      let totalLessons = 0;
      const lessonsRef = collection(db, LESSONS_COLLECTION);
      for (const modId of moduleIds) {
          const q = query(lessonsRef, where('moduleId', '==', modId));
          const snapshot = await getCountFromServer(q);
          totalLessons += snapshot.data().count;
