        <BottomControls 
            onZoomIn={() => setScale(s => Math.min(s + 0.1, 5))}
            onZoomOut={() => setScale(s => Math.max(s - 0.1, 0.1))}
            onReset={fitView}
            onSave={handleSave}
            onClose={onClose}
            scale={scale}
        />

        {isNoteEditorOpen && (
            <PostItEditor 
                initialNote={editingNote}
                onSave={handleSaveNote}
                onCancel={() => setIsNoteEditorOpen(false)}
            />
        )}

        {viewingNode && (
            <PostItViewer 
                notes={viewingNode.notes || []}
