import React, { useState } from 'react';
import { ChevronUp, ChevronDown, ChevronRight, Trash2, Plus, BookOpen } from 'lucide-react';
import { AdminCourseEditalTopic } from './AdminCourseEditalTopic';
// 1. IMPORTAR O MODAL DE CONFIRMAÇÃO
import { ConfirmationModal } from '../../../ui/ConfirmationModal';

interface AdminEditalDisciplineItemProps {
  discipline: any;
  courseId: string;
  onUpdate: (updatedDiscipline: any) => void;
  onDelete: () => void;
  onMoveUp: () => void;
  onMoveDown: () => void;
  isFirst: boolean;
  isLast: boolean;
}

export function AdminEditalDisciplineItem({ 
  discipline, courseId, onUpdate, onDelete, onMoveUp, onMoveDown, isFirst, isLast 
}: AdminEditalDisciplineItemProps) {

  const [isOpen, setIsOpen] = useState(false);

  // 2. NOVOS ESTADOS PARA O MODAL DE EXCLUSÃO DE TÓPICOS
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [topicToDelete, setTopicToDelete] = useState<string | null>(null);

  const handleMoveTopic = (index: number, direction: 'up' | 'down') => {
    // ... (sua lógica de reordenação existente mantém-se igual)
    const topics = discipline.topics || [];
    if ((direction === 'up' && index === 0) || (direction === 'down' && index === topics.length - 1)) return;
    const newTopics = [...topics];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    [newTopics[index], newTopics[targetIndex]] = [newTopics[targetIndex], newTopics[index]];
    onUpdate({ ...discipline, topics: newTopics });
  };

  // 3. FUNÇÃO PARA ABRIR O MODAL
  const handleDeleteTopicClick = (topicId: string) => {
    setTopicToDelete(topicId);
    setIsDeleteModalOpen(true);
  };

  // 4. FUNÇÃO PARA CONFIRMAR A EXCLUSÃO DO TÓPICO
  const confirmDeleteTopic = () => {
    if (!topicToDelete) return;

    // Filtra removendo o tópico selecionado
    const newTopics = (discipline.topics || []).filter((t: any) => t.id !== topicToDelete);

    // Atualiza o pai (que por sua vez salvará no Firebase)
    onUpdate({ ...discipline, topics: newTopics });

    // Fecha o modal
    setIsDeleteModalOpen(false);
    setTopicToDelete(null);
  };

  return (
    <div className="border border-gray-800 rounded-xl bg-[#1a1d24] overflow-hidden transition-all">

      {/* ... (Header da disciplina mantém-se igual) ... */}

      {isOpen && (
        <div className="p-4 pt-0 border-t border-gray-800/50 bg-black/20">
          <div className="pl-4 border-l-2 border-gray-800 mt-4 space-y-3">
            {!discipline.topics || discipline.topics.length === 0 ? (
               <div className="text-xs text-gray-600 italic">Nenhum tópico cadastrado. Adicione um acima.</div>
            ) : (
               discipline.topics.map((topic: any, index: number) => (
                 <AdminCourseEditalTopic 
                    key={topic.id}
                    topic={topic}
                    courseId={courseId}
                    onMoveUp={() => handleMoveTopic(index, 'up')}
                    onMoveDown={() => handleMoveTopic(index, 'down')}
                    isFirst={index === 0}
                    isLast={index === discipline.topics.length - 1}
                    onUpdate={(updatedTopic) => {
                       const newTopics = [...discipline.topics];
                       newTopics[index] = updatedTopic;
                       onUpdate({ ...discipline, topics: newTopics });
                    }}
                    // 5. PASSA A FUNÇÃO QUE ABRE O MODAL PARA O TÓPICO
                    onDelete={() => handleDeleteTopicClick(topic.id)}
                 />
               ))
            )}
          </div>
        </div>
      )}

      {/* 6. RENDERIZA O MODAL DE CONFIRMAÇÃO */}
      <ConfirmationModal 
        isOpen={isDeleteModalOpen}
        onClose={() => {
          setIsDeleteModalOpen(false);
          setTopicToDelete(null);
        }}
        onConfirm={confirmDeleteTopic}
        title="Excluir Tópico?"
        message="Tem certeza que deseja excluir este tópico? Todos os subtópicos e materiais vinculados serão perdidos."
        variant="danger"
      />
    </div>
  );
}

