import React, { useState, useRef } from 'react';
import { createPortal } from 'react-dom';
import { 
  Plus, Trash2, ChevronRight, ChevronDown, 
  PlayCircle, FileText, BrainCircuit, Layers, X, Link as LinkIcon,
  ArrowUp, ArrowDown, GripVertical
} from 'lucide-react';
import { CourseEditalTopic, LinkedLesson, MaterialPDF } from '../../../../../types/courseEdital';
import { courseService } from '../../../../../services/courseService';

// REUTILIZAÇÃO: Importando componentes existentes do módulo de Planos
import MindMapManager from '../../metas/tools/mindmap/MindMapManager';
import FlashcardEditor from '../../metas/tools/FlashcardEditor';
import { LinkLessonModal } from './LinkLessonModal';
import { ConfirmationModal } from '../../ui/ConfirmationModal';

interface Props {
  topic: CourseEditalTopic;
  onUpdate: (updated: CourseEditalTopic) => void;
  onDelete: () => void;
  depth?: number;
  courseId: string;
  // Props de reordenação recebidas do pai (Seja Disciplina ou Outro Tópico)
  onMoveUp: () => void;
  onMoveDown: () => void;
  isFirst: boolean;
  isLast: boolean;
}

const generateId = () => Math.random().toString(36).substr(2, 9);

export const AdminCourseEditalTopic: React.FC<Props> = ({ 
    topic, onUpdate, onDelete, depth = 0, courseId,
    onMoveUp, onMoveDown, isFirst, isLast
}) => {
  const [isExpanded, setIsExpanded] = useState(false); // Começa fechado para limpeza visual
  const [isEditingName, setIsEditingName] = useState(false);
  const [localName, setLocalName] = useState(topic.name);
  const [isUploading, setIsUploading] = useState(false);

  // Estados para Modais das Ferramentas e Vínculos
  const [activeTool, setActiveTool] = useState<'MAP' | 'FLASHCARD' | 'LESSON_LINK' | null>(null);

  // Estados para Modal de Exclusão de Subtópico
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [subtopicToDelete, setSubtopicToDelete] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handlers Básicos
  const handleNameBlur = () => {
    setIsEditingName(false);
    if (localName !== topic.name) {
        onUpdate({ ...topic, name: localName });
    }
  };

  const handleAddSubtopic = (e: React.MouseEvent) => {
    e.stopPropagation();
    const newSub: CourseEditalTopic = {
        id: generateId(),
        name: 'Novo Subtópico',
        subtopics: [],
        linkedLessons: [],
        materialPdfs: [],
        contentData: { mindMap: [], flashcards: [] }
    };
    onUpdate({ ...topic, subtopics: [...topic.subtopics, newSub] });
    setIsExpanded(true);
  };

  const handleSubtopicUpdate = (updatedSub: CourseEditalTopic) => {
    onUpdate({
        ...topic,
        subtopics: topic.subtopics.map(s => s.id === updatedSub.id ? updatedSub : s)
    });
  };

  // Solicita exclusão (Abre Modal)
  const handleSubtopicDeleteRequest = (subId: string) => {
    setSubtopicToDelete(subId);
    setIsDeleteModalOpen(true);
  };

  // Confirma exclusão
  const confirmSubtopicDelete = () => {
    if(subtopicToDelete) {
        onUpdate({
            ...topic,
            subtopics: topic.subtopics.filter(s => s.id !== subtopicToDelete)
        });
        setIsDeleteModalOpen(false);
        setSubtopicToDelete(null);
    }
  };

  // --- REORDENAÇÃO DE SUBTÓPICOS ---
  const handleMoveSubtopic = (index: number, direction: 'up' | 'down') => {
      const subs = topic.subtopics;
      if ((direction === 'up' && index === 0) || (direction === 'down' && index === subs.length - 1)) return;

      const newSubs = [...subs];
      const targetIndex = direction === 'up' ? index - 1 : index + 1;

      [newSubs[index], newSubs[targetIndex]] = [newSubs[targetIndex], newSubs[index]];

      onUpdate({ ...topic, subtopics: newSubs });
  };

  // Handlers de Ferramentas IA (Reutilização)
  const handleUpdateMindMap = (nodes: any[]) => {
    onUpdate({
        ...topic,
        contentData: { ...topic.contentData, mindMap: nodes }
    });
  };

  const handleUpdateFlashcards = (cards: any[]) => {
    onUpdate({
        ...topic,
        contentData: { ...topic.contentData, flashcards: cards }
    });
  };

  // --- LOGICA DE AULAS VINCULADAS ---
  const handleSaveLinkedLessons = (selectedLessons: LinkedLesson[]) => {
      onUpdate({
          ...topic,
          linkedLessons: selectedLessons
      });
  };

  const handleRemoveLesson = (lessonId: string) => {
      const newLessons = (topic.linkedLessons || []).filter(l => l.id !== lessonId);
      onUpdate({ ...topic, linkedLessons: newLessons });
  };

  // --- LOGICA DE UPLOAD DE PDF ---
  const handleUploadPDFClick = () => fileInputRef.current?.click();

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          setIsUploading(true);
          try {
              const result = await courseService.uploadEditalFile(file, courseId, topic.id);
              const newPdf: MaterialPDF = {
                  title: file.name,
                  url: result.url,
                  storagePath: result.path
              };
              const updatedPdfs = [...(topic.materialPdfs || []), newPdf];
              onUpdate({ ...topic, materialPdfs: updatedPdfs });
          } catch (error) {
              alert("Erro ao fazer upload do PDF.");
          } finally {
              setIsUploading(false);
              // Limpa o input para permitir selecionar o mesmo arquivo novamente
              if (fileInputRef.current) fileInputRef.current.value = '';
          }
      }
  };

  const handleRemovePDF = (url: string) => {
      const newPdfs = (topic.materialPdfs || []).filter(p => p.url !== url);
      onUpdate({ ...topic, materialPdfs: newPdfs });
      // TODO: Idealmente chamar serviço para deletar do Storage usando storagePath
  };


  // Badges e Contadores
  const mapCount = topic.contentData?.mindMap?.length || 0;
  const flashCount = topic.contentData?.flashcards?.length || 0;
  const lessonsCount = topic.linkedLessons?.length || 0;
  const pdfsCount = topic.materialPdfs?.length || 0;
  const subtopicsCount = topic.subtopics?.length || 0;

  // Cores de indentação e estilo visual
  const isSubtopic = depth > 0;
  const containerClass = isSubtopic 
    ? "bg-[#121418] border-l-2 border-l-zinc-700 ml-4 my-1" 
    : "bg-zinc-900 border border-zinc-800 my-1 rounded-lg";

  return (
    <div className={`flex flex-col ${containerClass} transition-all animate-in fade-in`}>

      <div 
        className={`flex items-center justify-between group hover:bg-zinc-800/50 p-2 transition-colors cursor-pointer ${isSubtopic ? 'rounded-r' : 'rounded'}`} 
        onClick={() => setIsExpanded(!isExpanded)}
      >
        <div className="flex items-center gap-2 flex-1 min-w-0">
          {/* Expander - Só mostra se tiver conteúdo filho ou vinculado, ou para indicar que pode expandir */}
          <button 
             className={`text-zinc-500 hover:text-white transition-colors w-5 flex justify-center`}
          >
             {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </button>

          {/* Nome Editável */}
          {isEditingName ? (
              <input 
                 value={localName}
                 onChange={(e) => setLocalName(e.target.value)}
                 onBlur={handleNameBlur}
                 onClick={e => e.stopPropagation()}
                 autoFocus
                 className="bg-black border border-zinc-600 rounded px-2 py-0.5 text-xs text-white focus:outline-none focus:border-blue-500 w-full max-w-[400px]"
              />
          ) : (
              <div className="flex items-center gap-2 overflow-hidden flex-wrap">
                <span 
                    onClick={(e) => { e.stopPropagation(); setIsEditingName(true); }}
                    className={`hover:text-white text-xs cursor-text transition-colors truncate font-medium ${isSubtopic ? 'text-zinc-400' : 'text-zinc-200'}`}
                >
                    {topic.name}
                </span>

                {/* Badges de Conteúdo */}
                {lessonsCount > 0 && <span className="text-[9px] bg-blue-500/10 text-blue-400 px-1.5 py-0.5 rounded border border-blue-500/20 flex items-center gap-0.5"><PlayCircle size={8}/> {lessonsCount}</span>}
                {pdfsCount > 0 && <span className="text-[9px] bg-orange-500/10 text-orange-400 px-1.5 py-0.5 rounded border border-orange-500/20 flex items-center gap-0.5"><FileText size={8}/> {pdfsCount}</span>}
                {mapCount > 0 && <span className="text-[9px] bg-purple-500/10 text-purple-400 px-1.5 py-0.5 rounded border border-purple-500/20 flex items-center gap-0.5"><BrainCircuit size={8}/> Mapa</span>}
                {flashCount > 0 && <span className="text-[9px] bg-pink-500/10 text-pink-400 px-1.5 py-0.5 rounded border border-pink-500/20 flex items-center gap-0.5"><Layers size={8}/> Cards</span>}
              </div>
          )}
        </div>

        {/* Action Buttons (Visible on Hover) */}
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity" onClick={e => e.stopPropagation()}>

            {/* Controles de Movimentação */}
            <div className="flex items-center bg-black/40 rounded border border-zinc-800 mr-2">
                <button 
                    onClick={onMoveUp} 
                    disabled={isFirst}
                    className="p-1 text-zinc-500 hover:text-white hover:bg-zinc-700 rounded-l disabled:opacity-20 disabled:hover:bg-transparent"
                    title="Mover para Cima"
                >
                    <ArrowUp size={10} />
                </button>
                <div className="w-px h-3 bg-zinc-800"></div>
                <button 
                    onClick={onMoveDown} 
                    disabled={isLast}
                    className="p-1 text-zinc-500 hover:text-white hover:bg-zinc-700 rounded-r disabled:opacity-20 disabled:hover:bg-transparent"
                    title="Mover para Baixo"
                >
                    <ArrowDown size={10} />
                </button>
            </div>

            {/* Quick Link Buttons */}
            <div className="flex bg-zinc-900 border border-zinc-800 rounded mr-2 overflow-hidden shadow-sm">
                <button onClick={() => setActiveTool('LESSON_LINK')} className="p-1.5 text-blue-500 hover:bg-blue-900/30 hover:text-blue-400" title="Vincular Aulas">
                    <PlayCircle size={12} />
                </button>
                <div className="w-px bg-zinc-800"></div>

                <button onClick={handleUploadPDFClick} disabled={isUploading} className="p-1.5 text-orange-500 hover:bg-orange-900/30 hover:text-orange-400 disabled:opacity-50" title="Upload PDF">
                    {isUploading ? <span className="animate-spin text-[8px]">↻</span> : <FileText size={12} />}
                </button>
                <input type="file" ref={fileInputRef} accept="application/pdf" className="hidden" onChange={handleFileChange} />

                <div className="w-px bg-zinc-800"></div>
                <button onClick={() => setActiveTool('MAP')} className="p-1.5 text-purple-500 hover:bg-purple-900/30 hover:text-purple-400" title="Mapa Mental"><BrainCircuit size={12} /></button>
                <div className="w-px bg-zinc-800"></div>
                <button onClick={() => setActiveTool('FLASHCARD')} className="p-1.5 text-pink-500 hover:bg-pink-900/30 hover:text-pink-400" title="Flashcards"><Layers size={12} /></button>
            </div>

            <button onClick={handleAddSubtopic} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded" title="Adicionar Subtópico">
                <Plus size={14} />
            </button>
            <button onClick={onDelete} className="p-1.5 text-zinc-500 hover:text-red-500 hover:bg-red-900/20 rounded" title="Excluir">
                <Trash2 size={14} />
            </button>
        </div>
      </div>

      {/* ÁREA DE CONTEÚDO (EXPANDIDA) */}
      {isExpanded && (
          <div className="pl-6 pr-2 pb-2 space-y-1 animate-in slide-in-from-top-1 duration-200">

              {/* Vínculos de Aulas */}
              {topic.linkedLessons && topic.linkedLessons.length > 0 && (
                  <div className="flex flex-wrap gap-2 pt-1">
                      {topic.linkedLessons.map(lesson => (
                          <div key={lesson.id} className="flex items-center gap-1.5 bg-blue-500/10 border border-blue-500/20 px-2 py-1 rounded text-[10px] text-blue-300 group/item hover:border-blue-500/40">
                              <PlayCircle size={10} />
                              <span className="truncate max-w-[150px]">{lesson.title}</span>
                              <button onClick={() => handleRemoveLesson(lesson.id)} className="hover:text-red-400 opacity-0 group-hover/item:opacity-100 transition-opacity ml-1"><X size={10} /></button>
                          </div>
                      ))}
                  </div>
              )}

              {/* Vínculos de PDF */}
              {topic.materialPdfs && topic.materialPdfs.length > 0 && (
                  <div className="flex flex-wrap gap-2 pt-1">
                      {topic.materialPdfs.map((pdf, idx) => (
                          <div key={idx} className="flex items-center gap-1.5 bg-orange-500/10 border border-orange-500/20 px-2 py-1 rounded text-[10px] text-orange-300 group/item hover:border-orange-500/40">
                              <FileText size={10} />
                              <span className="truncate max-w-[150px]">{pdf.title}</span>
                              <button onClick={() => handleRemovePDF(pdf.url)} className="hover:text-red-400 opacity-0 group-hover/item:opacity-100 transition-opacity ml-1"><X size={10} /></button>
                          </div>
                      ))}
                  </div>
              )}

              {/* Renderização Recursiva de Subtópicos */}
              {topic.subtopics.length > 0 && (
                <div className="pt-1 flex flex-col gap-1">
                    {topic.subtopics.map((sub, index) => (
                        <AdminCourseEditalTopic 
                            key={sub.id}
                            topic={sub}
                            onUpdate={handleSubtopicUpdate}
                            onDelete={() => handleSubtopicDeleteRequest(sub.id)}
                            depth={depth + 1}
                            courseId={courseId}
                            // Props de Reordenação de Subtópicos
                            onMoveUp={() => handleMoveSubtopic(index, 'up')}
                            onMoveDown={() => handleMoveSubtopic(index, 'down')}
                            isFirst={index === 0}
                            isLast={index === topic.subtopics.length - 1}
                        />
                    ))}
                </div>
              )}

              {/* Mensagem de Vazio se expandido e sem conteúdo */}
              {topic.subtopics.length === 0 && lessonsCount === 0 && pdfsCount === 0 && (
                  <div className="text-[10px] text-zinc-600 italic pl-2">Nenhum conteúdo vinculado.</div>
              )}
          </div>
      )}

      {/* --- MODAIS --- */}

      {/* Modal de Vínculo de Aulas */}
      <LinkLessonModal 
        isOpen={activeTool === 'LESSON_LINK'}
        onClose={() => setActiveTool(null)}
        courseId={courseId}
        onSave={handleSaveLinkedLessons}
        initialSelectedIds={topic.linkedLessons?.map(l => l.id)}
      />

      {/* Modal Mapa Mental */}
      {activeTool === 'MAP' && createPortal(
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/90 backdrop-blur-sm p-6 animate-in fade-in">
            <div className="bg-zinc-950 border border-zinc-800 w-full max-w-5xl h-[85vh] rounded-2xl flex flex-col shadow-2xl overflow-hidden">
                <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-[#121418]">
                    <h3 className="text-white font-bold text-lg flex items-center gap-2">
                        <BrainCircuit className="text-purple-500" /> 
                        Mapa Mental: {topic.name}
                    </h3>
                    <button onClick={() => setActiveTool(null)} className="text-zinc-500 hover:text-white"><X size={24} /></button>
                </div>
                <div className="flex-1 overflow-y-auto p-6 bg-black/50 custom-scrollbar">
                    <MindMapManager 
                        nodes={topic.contentData?.mindMap || []} 
                        onChange={handleUpdateMindMap} 
                    />
                </div>
            </div>
        </div>,
        document.body
      )}

      {/* Modal Flashcards */}
      {activeTool === 'FLASHCARD' && createPortal(
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/90 backdrop-blur-sm p-6 animate-in fade-in">
            <div className="bg-zinc-950 border border-zinc-800 w-full max-w-4xl h-[85vh] rounded-2xl flex flex-col shadow-2xl overflow-hidden">
                <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-[#121418]">
                    <h3 className="text-white font-bold text-lg flex items-center gap-2">
                        <Layers className="text-pink-500" /> 
                        Flashcards: {topic.name}
                    </h3>
                    <button onClick={() => setActiveTool(null)} className="text-zinc-500 hover:text-white"><X size={24} /></button>
                </div>
                <div className="flex-1 overflow-y-auto p-6 bg-black/50 custom-scrollbar">
                    <FlashcardEditor 
                        cards={topic.contentData?.flashcards || []} 
                        onChange={handleUpdateFlashcards} 
                    />
                </div>
            </div>
        </div>,
        document.body
      )}

      {/* Modal de Confirmação de Exclusão */}
      <ConfirmationModal 
        isOpen={isDeleteModalOpen}
        onClose={() => {
            setIsDeleteModalOpen(false);
            setSubtopicToDelete(null);
        }}
        onConfirm={confirmSubtopicDelete}
        title="Excluir Subtópico?"
        message="Tem certeza que deseja excluir este subtópico? Todo o conteúdo vinculado será perdido."
        confirmText="Excluir"
        isDanger={true}
        onCancel={() => {
            setIsDeleteModalOpen(false);
            setSubtopicToDelete(null);
        }}
      />

    </div>
  );
};

import React, { useState } from 'react';
import { ChevronRight, Plus, Trash2, BookOpen, ArrowUp, ArrowDown } from 'lucide-react';
import { CourseEditalDiscipline, CourseEditalTopic } from '../../../../../types/courseEdital';
import { AdminCourseEditalTopic } from './AdminCourseEditalTopic';
import { ConfirmationModal } from '../../ui/ConfirmationModal';

interface Props {
  discipline: CourseEditalDiscipline;
  courseId: string;
  onUpdate: (updated: CourseEditalDiscipline) => void;
  onDelete: () => void;
  // Props de reordenação recebidas do pai (Manager)
  onMoveUp: () => void;
  onMoveDown: () => void;
  isFirst: boolean;
  isLast: boolean;
}

const generateId = () => Math.random().toString(36).substr(2, 9);

export const AdminCourseEditalDiscipline: React.FC<Props> = ({ 
    discipline, courseId, onUpdate, onDelete, 
    onMoveUp, onMoveDown, isFirst, isLast 
}) => {
  const [isOpen, setIsOpen] = useState(false); // Padrão fechado para melhor organização visual
  const [isEditingName, setIsEditingName] = useState(false);
  const [localName, setLocalName] = useState(discipline.name);

  // Estados para Modal de Exclusão de Tópico
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [topicToDelete, setTopicToDelete] = useState<string | null>(null);

  // Handlers de Edição de Nome
  const handleNameBlur = () => {
    setIsEditingName(false);
    if (localName !== discipline.name) {
        onUpdate({ ...discipline, name: localName });
    }
  };

  // Adicionar Novo Tópico
  const handleAddTopic = (e: React.MouseEvent) => {
    e.stopPropagation();
    const newTopic: CourseEditalTopic = {
        id: generateId(),
        name: 'Novo Tópico',
        subtopics: [],
        linkedLessons: [],
        materialPdfs: [],
        contentData: { mindMap: [], flashcards: [] }
    };
    onUpdate({
        ...discipline,
        topics: [...discipline.topics, newTopic]
    });
    setIsOpen(true); // Abre a pasta ao adicionar
  };

  // Atualizar Tópico
  const handleTopicUpdate = (updatedTopic: CourseEditalTopic) => {
    onUpdate({
        ...discipline,
        topics: discipline.topics.map(t => t.id === updatedTopic.id ? updatedTopic : t)
    });
  };

  // Solicitar Exclusão de Tópico (Abre Modal)
  const handleDeleteRequest = (topicId: string) => {
    setTopicToDelete(topicId);
    setIsDeleteModalOpen(true);
  };

  // Confirmar Exclusão de Tópico
  const confirmDeleteTopic = () => {
    if (topicToDelete) {
        onUpdate({
            ...discipline,
            topics: discipline.topics.filter(t => t.id !== topicToDelete)
        });
        setIsDeleteModalOpen(false);
        setTopicToDelete(null);
    }
  };

  // --- REORDENAÇÃO DE TÓPICOS (Lógica Interna) ---
  const handleMoveTopic = (index: number, direction: 'up' | 'down') => {
      const topics = discipline.topics || [];
      if ((direction === 'up' && index === 0) || (direction === 'down' && index === topics.length - 1)) return;

      const newTopics = [...topics];
      const targetIndex = direction === 'up' ? index - 1 : index + 1;

      // Swap
      [newTopics[index], newTopics[targetIndex]] = [newTopics[targetIndex], newTopics[index]];

      onUpdate({ ...discipline, topics: newTopics });
  };

  return (
    <div className="border border-zinc-800 rounded-lg overflow-hidden bg-[#15171b] mb-3 transition-all hover:border-zinc-700 shadow-sm">
      {/* Header (Clicável para Acordeão) */}
      <div 
        className={`flex items-center justify-between p-4 cursor-pointer group select-none transition-colors ${isOpen ? 'bg-[#1a1d24]' : 'hover:bg-[#1a1d24]'}`}
        onClick={() => setIsOpen(!isOpen)}
      >
        <div className="flex items-center gap-3 flex-1">
            <div className={`text-zinc-500 transition-transform duration-200 ${isOpen ? 'rotate-90' : ''}`}>
                <ChevronRight size={18} />
            </div>

            <div className="p-2 bg-red-600/10 rounded-lg border border-red-600/20 text-red-500">
                <BookOpen size={16} />
            </div>

            {isEditingName ? (
                <input 
                    value={localName}
                    onChange={(e) => setLocalName(e.target.value)}
                    onBlur={handleNameBlur}
                    onClick={(e) => e.stopPropagation()}
                    autoFocus
                    className="bg-black border border-zinc-700 rounded px-2 py-1 text-white text-sm font-bold uppercase w-64 focus:outline-none focus:border-red-500"
                />
            ) : (
                <span 
                    className="text-white font-bold uppercase text-sm hover:text-red-400 transition-colors"
                    onClick={(e) => { e.stopPropagation(); setIsEditingName(true); }}
                    title="Clique para editar nome"
                >
                    {discipline.name}
                </span>
            )}

            <span className="text-[10px] text-zinc-500 font-mono bg-black/30 px-2 py-0.5 rounded border border-zinc-800 ml-2">
                {discipline.topics.length} Tópicos
            </span>
        </div>

        <div className="flex items-center gap-2">

            {/* Controles de Movimentação da Disciplina (Pai) */}
            <div className="flex items-center bg-black/40 rounded border border-zinc-800 mr-2" onClick={e => e.stopPropagation()}>
                <button 
                    onClick={onMoveUp} 
                    disabled={isFirst}
                    className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded-l disabled:opacity-30 disabled:hover:bg-transparent"
                    title="Mover Disciplina para Cima"
                >
                    <ArrowUp size={12} />
                </button>
                <div className="w-px h-4 bg-zinc-800"></div>
                <button 
                    onClick={onMoveDown} 
                    disabled={isLast}
                    className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded-r disabled:opacity-30 disabled:hover:bg-transparent"
                    title="Mover Disciplina para Baixo"
                >
                    <ArrowDown size={12} />
                </button>
            </div>

            <button 
                onClick={handleAddTopic}
                className="px-3 py-1.5 bg-zinc-800 hover:bg-zinc-700 text-white rounded text-[10px] font-bold flex items-center gap-1 border border-zinc-700 uppercase transition-all"
            >
                <Plus size={12} /> Tópico
            </button>
            <button 
                onClick={(e) => { e.stopPropagation(); onDelete(); }}
                className="p-1.5 text-zinc-500 hover:text-red-500 hover:bg-red-500/10 rounded transition-colors"
                title="Excluir Disciplina"
            >
                <Trash2 size={16} />
            </button>
        </div>
      </div>

      {/* Body (Lista de Tópicos) */}
      {isOpen && (
        <div className="bg-black/20 p-2 pl-4 border-t border-zinc-800 space-y-2 animate-in slide-in-from-top-2 duration-200">
            {discipline.topics.length === 0 ? (
                <div className="text-center py-6 text-zinc-600 text-xs italic">
                    Nenhum tópico cadastrado. Adicione um acima.
                </div>
            ) : (
                discipline.topics.map((topic, index) => (
                    <AdminCourseEditalTopic 
                        key={topic.id}
                        topic={topic}
                        courseId={courseId}
                        onUpdate={handleTopicUpdate}
                        // Passamos a função de solicitação de exclusão
                        onDelete={() => handleDeleteRequest(topic.id)}
                        // Passando função de reordenação para o filho
                        onMoveUp={() => handleMoveTopic(index, 'up')}
                        onMoveDown={() => handleMoveTopic(index, 'down')}
                        isFirst={index === 0}
                        isLast={index === discipline.topics.length - 1}
                    />
                ))
            )}
        </div>
      )}

      {/* Modal de Confirmação de Exclusão */}
      <ConfirmationModal 
        isOpen={isDeleteModalOpen}
        onClose={() => {
            setIsDeleteModalOpen(false);
            setTopicToDelete(null);
        }}
        onConfirm={confirmDeleteTopic}
        title="Excluir Tópico?"
        message="Tem certeza que deseja excluir este tópico? Todos os subtópicos e materiais vinculados serão perdidos."
        confirmText="Excluir"
        isDanger={true}
        onCancel={() => {
            setIsDeleteModalOpen(false);
            setTopicToDelete(null);
        }}
      />
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { createPortal } from 'react-dom';
import { 
  Plus, Trash2, ChevronRight, ChevronDown, 
  PlayCircle, FileText, BrainCircuit, Layers, X, Link as LinkIcon,
  ArrowUp, ArrowDown, GripVertical
} from 'lucide-react';
import { CourseEditalTopic, LinkedLesson, MaterialPDF } from '../../../../../types/courseEdital';
import { courseService } from '../../../../../services/courseService';

// REUTILIZAÇÃO: Importando componentes existentes do módulo de Planos
import MindMapManager from '../../metas/tools/mindmap/MindMapManager';
import FlashcardEditor from '../../metas/tools/FlashcardEditor';
import { LinkLessonModal } from './LinkLessonModal';
import { ConfirmationModal } from '../../../../components/ui/ConfirmationModal';

interface Props {
  topic: CourseEditalTopic;
  onUpdate: (updated: CourseEditalTopic) => void;
  onDelete: () => void;
  depth?: number;
  courseId: string;
  // Props de reordenação recebidas do pai (Seja Disciplina ou Outro Tópico)
  onMoveUp: () => void;
  onMoveDown: () => void;
  isFirst: boolean;
  isLast: boolean;
}

const generateId = () => Math.random().toString(36).substr(2, 9);

export const AdminCourseEditalTopic: React.FC<Props> = ({ 
    topic, onUpdate, onDelete, depth = 0, courseId,
    onMoveUp, onMoveDown, isFirst, isLast
}) => {
  const [isExpanded, setIsExpanded] = useState(false); // Começa fechado para limpeza visual
  const [isEditingName, setIsEditingName] = useState(false);
  const [localName, setLocalName] = useState(topic.name);
  const [isUploading, setIsUploading] = useState(false);

  // Estados para Modais das Ferramentas e Vínculos
  const [activeTool, setActiveTool] = useState<'MAP' | 'FLASHCARD' | 'LESSON_LINK' | null>(null);

  // Estados para Modal de Exclusão de Subtópico
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [subtopicToDelete, setSubtopicToDelete] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handlers Básicos
  const handleNameBlur = () => {
    setIsEditingName(false);
    if (localName !== topic.name) {
        onUpdate({ ...topic, name: localName });
    }
  };

  const handleAddSubtopic = (e: React.MouseEvent) => {
    e.stopPropagation();
    const newSub: CourseEditalTopic = {
        id: generateId(),
        name: 'Novo Subtópico',
        subtopics: [],
        linkedLessons: [],
        materialPdfs: [],
        contentData: { mindMap: [], flashcards: [] }
    };
    onUpdate({ ...topic, subtopics: [...topic.subtopics, newSub] });
    setIsExpanded(true);
  };

  const handleSubtopicUpdate = (updatedSub: CourseEditalTopic) => {
    onUpdate({
        ...topic,
        subtopics: topic.subtopics.map(s => s.id === updatedSub.id ? updatedSub : s)
    });
  };

  // Solicita exclusão (Abre Modal)
  const handleSubtopicDeleteRequest = (subId: string) => {
    setSubtopicToDelete(subId);
    setIsDeleteModalOpen(true);
  };

  // Confirma exclusão
  const confirmSubtopicDelete = () => {
    if(subtopicToDelete) {
        onUpdate({
            ...topic,
            subtopics: topic.subtopics.filter(s => s.id !== subtopicToDelete)
        });
        setIsDeleteModalOpen(false);
        setSubtopicToDelete(null);
    }
  };

  // --- REORDENAÇÃO DE SUBTÓPICOS ---
  const handleMoveSubtopic = (index: number, direction: 'up' | 'down') => {
      const subs = topic.subtopics;
      if ((direction === 'up' && index === 0) || (direction === 'down' && index === subs.length - 1)) return;

      const newSubs = [...subs];
      const targetIndex = direction === 'up' ? index - 1 : index + 1;

      [newSubs[index], newSubs[targetIndex]] = [newSubs[targetIndex], newSubs[index]];

      onUpdate({ ...topic, subtopics: newSubs });
  };

  // Handlers de Ferramentas IA (Reutilização)
  const handleUpdateMindMap = (nodes: any[]) => {
    onUpdate({
        ...topic,
        contentData: { ...topic.contentData, mindMap: nodes }
    });
  };

  const handleUpdateFlashcards = (cards: any[]) => {
    onUpdate({
        ...topic,
        contentData: { ...topic.contentData, flashcards: cards }
    });
  };

  // --- LOGICA DE AULAS VINCULADAS ---
  const handleSaveLinkedLessons = (selectedLessons: LinkedLesson[]) => {
      onUpdate({
          ...topic,
          linkedLessons: selectedLessons
      });
  };

  const handleRemoveLesson = (lessonId: string) => {
      const newLessons = (topic.linkedLessons || []).filter(l => l.id !== lessonId);
      onUpdate({ ...topic, linkedLessons: newLessons });
  };

  // --- LOGICA DE UPLOAD DE PDF ---
  const handleUploadPDFClick = () => fileInputRef.current?.click();

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          setIsUploading(true);
          try {
              const result = await courseService.uploadEditalFile(file, courseId, topic.id);
              const newPdf: MaterialPDF = {
                  title: file.name,
                  url: result.url,
                  storagePath: result.path
              };
              const updatedPdfs = [...(topic.materialPdfs || []), newPdf];
              onUpdate({ ...topic, materialPdfs: updatedPdfs });
          } catch (error) {
              alert("Erro ao fazer upload do PDF.");
          } finally {
              setIsUploading(false);
              // Limpa o input para permitir selecionar o mesmo arquivo novamente
              if (fileInputRef.current) fileInputRef.current.value = '';
          }
      }
  };

  const handleRemovePDF = (url: string) => {
      const newPdfs = (topic.materialPdfs || []).filter(p => p.url !== url);
      onUpdate({ ...topic, materialPdfs: newPdfs });
      // TODO: Idealmente chamar serviço para deletar do Storage usando storagePath
  };


  // Badges e Contadores
  const mapCount = topic.contentData?.mindMap?.length || 0;
  const flashCount = topic.contentData?.flashcards?.length || 0;
  const lessonsCount = topic.linkedLessons?.length || 0;
  const pdfsCount = topic.materialPdfs?.length || 0;
  const subtopicsCount = topic.subtopics?.length || 0;

  // Cores de indentação e estilo visual
  const isSubtopic = depth > 0;
  const containerClass = isSubtopic 
    ? "bg-[#121418] border-l-2 border-l-zinc-700 ml-4 my-1" 
    : "bg-zinc-900 border border-zinc-800 my-1 rounded-lg";

  return (
    <div className={`flex flex-col ${containerClass} transition-all animate-in fade-in`}>

      <div 
        className={`flex items-center justify-between group hover:bg-zinc-800/50 p-2 transition-colors cursor-pointer ${isSubtopic ? 'rounded-r' : 'rounded'}`} 
        onClick={() => setIsExpanded(!isExpanded)}
      >
        <div className="flex items-center gap-2 flex-1 min-w-0">
          {/* Expander - Só mostra se tiver conteúdo filho ou vinculado, ou para indicar que pode expandir */}
          <button 
             className={`text-zinc-500 hover:text-white transition-colors w-5 flex justify-center`}
          >
             {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </button>

          {/* Nome Editável */}
          {isEditingName ? (
              <input 
                 value={localName}
                 onChange={(e) => setLocalName(e.target.value)}
                 onBlur={handleNameBlur}
                 onClick={e => e.stopPropagation()}
                 autoFocus
                 className="bg-black border border-zinc-600 rounded px-2 py-0.5 text-xs text-white focus:outline-none focus:border-blue-500 w-full max-w-[400px]"
              />
          ) : (
              <div className="flex items-center gap-2 overflow-hidden flex-wrap">
                <span 
                    onClick={(e) => { e.stopPropagation(); setIsEditingName(true); }}
                    className={`hover:text-white text-xs cursor-text transition-colors truncate font-medium ${isSubtopic ? 'text-zinc-400' : 'text-zinc-200'}`}
                >
                    {topic.name}
                </span>

                {/* Badges de Conteúdo */}
                {lessonsCount > 0 && <span className="text-[9px] bg-blue-500/10 text-blue-400 px-1.5 py-0.5 rounded border border-blue-500/20 flex items-center gap-0.5"><PlayCircle size={8}/> {lessonsCount}</span>}
                {pdfsCount > 0 && <span className="text-[9px] bg-orange-500/10 text-orange-400 px-1.5 py-0.5 rounded border border-orange-500/20 flex items-center gap-0.5"><FileText size={8}/> {pdfsCount}</span>}
                {mapCount > 0 && <span className="text-[9px] bg-purple-500/10 text-purple-400 px-1.5 py-0.5 rounded border border-purple-500/20 flex items-center gap-0.5"><BrainCircuit size={8}/> Mapa</span>}
                {flashCount > 0 && <span className="text-[9px] bg-pink-500/10 text-pink-400 px-1.5 py-0.5 rounded border border-pink-500/20 flex items-center gap-0.5"><Layers size={8}/> Cards</span>}
              </div>
          )}
        </div>

        {/* Action Buttons (Visible on Hover) */}
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity" onClick={e => e.stopPropagation()}>

            {/* Controles de Movimentação */}
            <div className="flex items-center bg-black/40 rounded border border-zinc-800 mr-2">
                <button 
                    onClick={onMoveUp} 
                    disabled={isFirst}
                    className="p-1 text-zinc-500 hover:text-white hover:bg-zinc-700 rounded-l disabled:opacity-20 disabled:hover:bg-transparent"
                    title="Mover para Cima"
                >
                    <ArrowUp size={10} />
                </button>
                <div className="w-px h-3 bg-zinc-800"></div>
                <button 
                    onClick={onMoveDown} 
                    disabled={isLast}
                    className="p-1 text-zinc-500 hover:text-white hover:bg-zinc-700 rounded-r disabled:opacity-20 disabled:hover:bg-transparent"
                    title="Mover para Baixo"
                >
                    <ArrowDown size={10} />
                </button>
            </div>

            {/* Quick Link Buttons */}
            <div className="flex bg-zinc-900 border border-zinc-800 rounded mr-2 overflow-hidden shadow-sm">
                <button onClick={() => setActiveTool('LESSON_LINK')} className="p-1.5 text-blue-500 hover:bg-blue-900/30 hover:text-blue-400" title="Vincular Aulas">
                    <PlayCircle size={12} />
                </button>
