import { MindMapNode, Flashcard } from '../services/metaService';

export interface LinkedLesson {
  id: string; // lessonId
  title: string;
  moduleId: string;
}

export interface MaterialPDF {
  title: string;
  url: string;
  storagePath?: string; // Para facilitar exclusão futura
}

export interface CourseEditalTopic {
  id: string;
  name: string;
  subtopics: CourseEditalTopic[];

  // Novo Campo: Observação Rica
  observation?: string;

  // Conteúdos Vinculados/Criados
  linkedLessons?: LinkedLesson[];
  materialPdfs?: MaterialPDF[];

  // Conteúdo Gerado por IA
  contentData?: {
    mindMap?: MindMapNode[];
    flashcards?: Flashcard[];
  };
}

export interface CourseEditalDiscipline {
  id: string;
  name: string;
  topics: CourseEditalTopic[];
}

export interface CourseEditalStructure {
  courseId: string;
  status: 'PRE_EDITAL' | 'POS_EDITAL';
  disciplines: CourseEditalDiscipline[];
  updatedAt: any;
}

import React, { useRef, useEffect } from 'react';
import { 
  Bold, Italic, Underline, Strikethrough, 
  AlignLeft, AlignCenter, AlignRight, AlignJustify,
  Link as LinkIcon, Type, List, ListOrdered
} from 'lucide-react';

interface RichTextEditorProps {
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
}

export function RichTextEditor({ value, onChange, placeholder }: RichTextEditorProps) {
  // Referência direta ao elemento DOM editável
  const editorRef = useRef<HTMLDivElement>(null);

  // CORREÇÃO TÉCNICA: Sincronização via useEffect
  // Isso garante que o HTML só seja atualizado se vier de fora (ex: carregamento inicial)
  // e não interfere enquanto o usuário está digitando (preservando o cursor).
  useEffect(() => {
    if (editorRef.current) {
      // Só atualiza o DOM se o conteúdo for diferente para evitar loop de renderização
      if (editorRef.current.innerHTML !== value) {
        editorRef.current.innerHTML = value;
      }
    }
  }, [value]);

  // Função para executar comandos de formatação (Bold, Italic, etc)
  const execCommand = (command: string, arg: string | undefined = undefined) => {
    document.execCommand(command, false, arg);
    // Força atualização do estado após o comando
    if (editorRef.current) {
      onChange(editorRef.current.innerHTML);
    }
    // Mantém o foco no editor
    editorRef.current?.focus();
  };

  const handleLink = () => {
    const url = prompt('Insira a URL do link:');
    if (url) execCommand('createLink', url);
  };

  return (
    <div className="border border-gray-700 rounded-lg overflow-hidden bg-black flex flex-col h-full">

      {/* --- BARRA DE FERRAMENTAS --- */}
      <div className="flex flex-wrap items-center gap-1 p-2 border-b border-gray-700 bg-[#1a1d24]">

        {/* Estilos de Texto */}
        <ToolbarButton onClick={() => execCommand('bold')} icon={<Bold size={16} />} title="Negrito" />
        <ToolbarButton onClick={() => execCommand('italic')} icon={<Italic size={16} />} title="Itálico" />
        <ToolbarButton onClick={() => execCommand('underline')} icon={<Underline size={16} />} title="Sublinhado" />
        <ToolbarButton onClick={() => execCommand('strikeThrough')} icon={<Strikethrough size={16} />} title="Tachado" />

        <div className="w-px h-4 bg-gray-600 mx-1"></div>

        {/* Alinhamento */}
        <ToolbarButton onClick={() => execCommand('justifyLeft')} icon={<AlignLeft size={16} />} title="Esquerda" />
        <ToolbarButton onClick={() => execCommand('justifyCenter')} icon={<AlignCenter size={16} />} title="Centro" />
        <ToolbarButton onClick={() => execCommand('justifyRight')} icon={<AlignRight size={16} />} title="Direita" />
        <ToolbarButton onClick={() => execCommand('justifyFull')} icon={<AlignJustify size={16} />} title="Justificado" />

        <div className="w-px h-4 bg-gray-600 mx-1"></div>

        {/* Listas */}
        <ToolbarButton onClick={() => execCommand('insertUnorderedList')} icon={<List size={16} />} title="Lista com Marcadores" />
        <ToolbarButton onClick={() => execCommand('insertOrderedList')} icon={<ListOrdered size={16} />} title="Lista Numerada" />

        <div className="w-px h-4 bg-gray-600 mx-1"></div>

        {/* Formatação Avançada */}
        <select 
          onChange={(e) => execCommand('formatBlock', e.target.value)}
          className="bg-black border border-gray-600 text-gray-300 text-xs rounded px-2 py-1 outline-none focus:border-red-600"
          defaultValue="p"
        >
          <option value="p">Normal</option>
          <option value="h1">Título 1</option>
          <option value="h2">Título 2</option>
          <option value="h3">Título 3</option>
          <option value="blockquote">Citação</option>
        </select>

        {/* Cor do Texto (Input nativo escondido com label customizada) */}
        <div className="relative flex items-center justify-center w-7 h-7 hover:bg-gray-700 rounded cursor-pointer group">
            <input 
                type="color" 
                onChange={(e) => execCommand('foreColor', e.target.value)}
                className="absolute inset-0 opacity-0 w-full h-full cursor-pointer"
                title="Cor do Texto"
            />
            <Type size={16} className="text-gray-300" />
            <div className="absolute bottom-1 w-4 h-0.5 bg-red-600"></div>
        </div>

        <div className="w-px h-4 bg-gray-600 mx-1"></div>

        {/* Extras */}
        <ToolbarButton onClick={handleLink} icon={<LinkIcon size={16} />} title="Inserir Link" />

      </div>

      {/* --- ÁREA EDITÁVEL (CORRIGIDA) --- */}
      {/* Adicionado suporte CSS para listas visuais dentro do editor */}
      <style>{`
        .rich-content ul { list-style-type: disc; padding-left: 1.5em; }
        .rich-content ol { list-style-type: decimal; padding-left: 1.5em; }
        .rich-content blockquote { border-left: 4px solid #4b5563; padding-left: 1em; font-style: italic; color: #9ca3af; }
      `}</style>
      <div
        ref={editorRef}
        className="rich-content flex-1 p-4 text-gray-300 outline-none focus:bg-[#0f1114] transition-colors overflow-y-auto min-h-[150px] max-w-none text-sm"
        contentEditable
        onInput={(e) => onChange(e.currentTarget.innerHTML)}
        placeholder={placeholder}
        style={{ whiteSpace: 'pre-wrap' }} // Preserva quebras de linha
      />
    </div>
  );
}

// Botão auxiliar da Toolbar
const ToolbarButton = ({ onClick, icon, title }: { onClick: () => void, icon: React.ReactNode, title: string }) => (
  <button
    type="button"
    onClick={onClick}
    title={title}
    className="p-1.5 text-gray-400 hover:text-white hover:bg-gray-600 rounded transition-colors"
  >
    {icon}
  </button>
);

import React, { useState, useRef } from 'react';
import { createPortal } from 'react-dom';
import { 
  Plus, Trash2, ChevronRight, ChevronDown, 
  PlayCircle, FileText, BrainCircuit, Layers, X, Link as LinkIcon,
  ArrowUp, ArrowDown, StickyNote, Save
} from 'lucide-react';
import { CourseEditalTopic, LinkedLesson, MaterialPDF } from '../../../../../types/courseEdital';
import { courseService } from '../../../../../services/courseService';

import MindMapManager from '../../metas/tools/mindmap/MindMapManager';
import FlashcardEditor from '../../metas/tools/FlashcardEditor';
import { LinkLessonModal } from './LinkLessonModal';
import { ConfirmationModal } from '../../../../components/ui/ConfirmationModal';
import { RichTextEditor } from '../../../../components/ui/RichTextEditor';

interface Props {
  topic: CourseEditalTopic;
  onUpdate: (updated: CourseEditalTopic) => void;
  onDelete: () => void;
  depth?: number;
  courseId: string;
  onMoveUp: () => void;
  onMoveDown: () => void;
  isFirst: boolean;
  isLast: boolean;
}

const generateId = () => Math.random().toString(36).substr(2, 9);

export const AdminCourseEditalTopic: React.FC<Props> = ({ 
    topic, onUpdate, onDelete, depth = 0, courseId,
    onMoveUp, onMoveDown, isFirst, isLast
}) => {
  const [isExpanded, setIsExpanded] = useState(false);
  const [isEditingName, setIsEditingName] = useState(false);
  const [localName, setLocalName] = useState(topic.name);
  const [isUploading, setIsUploading] = useState(false);

  // Estados para Observação
  const [isEditingObservation, setIsEditingObservation] = useState(false);
  const [observationText, setObservationText] = useState(topic.observation || '');

  // Estados para Modais das Ferramentas
  const [activeTool, setActiveTool] = useState<'MAP' | 'FLASHCARD' | 'LESSON_LINK' | null>(null);

  // Estados para Modal de Exclusão de Subtópico
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [subtopicToDelete, setSubtopicToDelete] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // --- HANDLERS BÁSICOS ---
  const handleNameBlur = () => {
    setIsEditingName(false);
    if (localName !== topic.name) {
        onUpdate({ ...topic, name: localName });
    }
  };

  const handleAddSubtopic = (e: React.MouseEvent) => {
    e.stopPropagation();
    const newSub: CourseEditalTopic = {
        id: generateId(),
        name: 'Novo Subtópico',
        subtopics: [],
        linkedLessons: [],
        materialPdfs: [],
        contentData: { mindMap: [], flashcards: [] }
    };
    onUpdate({ ...topic, subtopics: [...topic.subtopics, newSub] });
    setIsExpanded(true);
  };

  const handleSubtopicUpdate = (updatedSub: CourseEditalTopic) => {
    onUpdate({
        ...topic,
        subtopics: topic.subtopics.map(s => s.id === updatedSub.id ? updatedSub : s)
    });
  };

  // --- OBSERVATION HANDLERS ---
  const handleSaveObservation = () => {
    onUpdate({ ...topic, observation: observationText });
    setIsEditingObservation(false);
  };

  const handleCancelObservation = () => {
    setObservationText(topic.observation || '');
    setIsEditingObservation(false);
  };

  // --- LÓGICA DE EXCLUSÃO DE SUBTÓPICO ---

  // 1. Solicita exclusão (Abre Modal)
  const handleSubtopicDeleteRequest = (subId: string) => {
    setSubtopicToDelete(subId);
    setIsDeleteModalOpen(true);
  };

  // 2. Confirma exclusão (Remove do array e fecha modal)
  const confirmSubtopicDelete = () => {
    if(subtopicToDelete) {
        onUpdate({
            ...topic,
            subtopics: topic.subtopics.filter(s => s.id !== subtopicToDelete)
        });
        setIsDeleteModalOpen(false);
        setSubtopicToDelete(null);
    }
  };

  // --- REORDENAÇÃO DE SUBTÓPICOS ---
  const handleMoveSubtopic = (index: number, direction: 'up' | 'down') => {
      const subs = topic.subtopics;
      if ((direction === 'up' && index === 0) || (direction === 'down' && index === subs.length - 1)) return;

      const newSubs = [...subs];
      const targetIndex = direction === 'up' ? index - 1 : index + 1;

      [newSubs[index], newSubs[targetIndex]] = [newSubs[targetIndex], newSubs[index]];

      onUpdate({ ...topic, subtopics: newSubs });
  };

  // --- HANDLERS DE CONTEÚDO (IA/LINK/PDF) ---
  const handleUpdateMindMap = (nodes: any[]) => {
    onUpdate({ ...topic, contentData: { ...topic.contentData, mindMap: nodes } });
  };

  const handleUpdateFlashcards = (cards: any[]) => {
    onUpdate({ ...topic, contentData: { ...topic.contentData, flashcards: cards } });
  };

  const handleSaveLinkedLessons = (selectedLessons: LinkedLesson[]) => {
      onUpdate({ ...topic, linkedLessons: selectedLessons });
  };

  const handleRemoveLesson = (lessonId: string) => {
      const newLessons = (topic.linkedLessons || []).filter(l => l.id !== lessonId);
      onUpdate({ ...topic, linkedLessons: newLessons });
  };

  const handleUploadPDFClick = () => fileInputRef.current?.click();

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          setIsUploading(true);
          try {
              const result = await courseService.uploadEditalFile(file, courseId, topic.id);
              const newPdf: MaterialPDF = {
                  title: file.name,
                  url: result.url,
                  storagePath: result.path
              };
              const updatedPdfs = [...(topic.materialPdfs || []), newPdf];
              onUpdate({ ...topic, materialPdfs: updatedPdfs });
          } catch (error) {
              alert("Erro ao fazer upload do PDF.");
          } finally {
              setIsUploading(false);
              if (fileInputRef.current) fileInputRef.current.value = '';
          }
      }
  };

  const handleRemovePDF = (url: string) => {
      const newPdfs = (topic.materialPdfs || []).filter(p => p.url !== url);
      onUpdate({ ...topic, materialPdfs: newPdfs });
  };


  // Badges e Estilos
  const mapCount = topic.contentData?.mindMap?.length || 0;
  const flashCount = topic.contentData?.flashcards?.length || 0;
  const lessonsCount = topic.linkedLessons?.length || 0;
  const pdfsCount = topic.materialPdfs?.length || 0;
  const hasObservation = !!topic.observation && topic.observation.trim() !== '<p><br></p>' && topic.observation.trim() !== '';

  const isSubtopic = depth > 0;
  const containerClass = isSubtopic 
    ? "bg-[#121418] border-l-2 border-l-zinc-700 ml-4 my-1" 
    : "bg-zinc-900 border border-zinc-800 my-1 rounded-lg";

  return (
    <div className={`flex flex-col ${containerClass} transition-all animate-in fade-in`}>

      {/* HEADER DO TÓPICO */}
      <div 
        className={`flex items-center justify-between group hover:bg-zinc-800/50 p-2 transition-colors cursor-pointer ${isSubtopic ? 'rounded-r' : 'rounded'}`} 
        onClick={() => setIsExpanded(!isExpanded)}
      >
        <div className="flex items-center gap-2 flex-1 min-w-0">
          <button className={`text-zinc-500 hover:text-white transition-colors w-5 flex justify-center`}>
             {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </button>

          {isEditingName ? (
              <input 
                 value={localName}
                 onChange={(e) => setLocalName(e.target.value)}
                 onBlur={handleNameBlur}
                 onClick={e => e.stopPropagation()}
                 autoFocus
                 className="bg-black border border-zinc-600 rounded px-2 py-0.5 text-xs text-white focus:outline-none focus:border-blue-500 w-full max-w-[400px]"
              />
          ) : (
              <div className="flex items-center gap-2 overflow-hidden flex-wrap">
                <span 
                    onClick={(e) => { e.stopPropagation(); setIsEditingName(true); }}
                    className={`hover:text-white text-xs cursor-text transition-colors truncate font-medium ${isSubtopic ? 'text-zinc-400' : 'text-zinc-200'}`}
                >
                    {topic.name}
                </span>

                {lessonsCount > 0 && <span className="text-[9px] bg-blue-500/10 text-blue-400 px-1.5 py-0.5 rounded border border-blue-500/20 flex items-center gap-0.5"><PlayCircle size={8}/> {lessonsCount}</span>}
                {pdfsCount > 0 && <span className="text-[9px] bg-orange-500/10 text-orange-400 px-1.5 py-0.5 rounded border border-orange-500/20 flex items-center gap-0.5"><FileText size={8}/> {pdfsCount}</span>}
                {mapCount > 0 && <span className="text-[9px] bg-purple-500/10 text-purple-400 px-1.5 py-0.5 rounded border border-purple-500/20 flex items-center gap-0.5"><BrainCircuit size={8}/> Mapa</span>}
                {flashCount > 0 && <span className="text-[9px] bg-pink-500/10 text-pink-400 px-1.5 py-0.5 rounded border border-pink-500/20 flex items-center gap-0.5"><Layers size={8}/> Cards</span>}
                {hasObservation && <span className="text-[9px] bg-yellow-500/10 text-yellow-400 px-1.5 py-0.5 rounded border border-yellow-500/20 flex items-center gap-0.5"><StickyNote size={8}/> Obs</span>}
              </div>
          )}
        </div>

        {/* BOTÕES DE AÇÃO (HOVER) */}
        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity" onClick={e => e.stopPropagation()}>

            {/* Reordenação */}
            <div className="flex items-center bg-black/40 rounded border border-zinc-800 mr-2">
                <button onClick={onMoveUp} disabled={isFirst} className="p-1 text-zinc-500 hover:text-white hover:bg-zinc-700 rounded-l disabled:opacity-20" title="Mover para Cima">
                    <ArrowUp size={10} />
                </button>
                <div className="w-px h-3 bg-zinc-800"></div>
                <button onClick={onMoveDown} disabled={isLast} className="p-1 text-zinc-500 hover:text-white hover:bg-zinc-700 rounded-r disabled:opacity-20" title="Mover para Baixo">
                    <ArrowDown size={10} />
                </button>
            </div>

            {/* Botão de Observação */}
            <button 
                onClick={() => { setIsEditingObservation(!isEditingObservation); setIsExpanded(true); }}
                className={`p-1.5 rounded mr-2 transition-colors ${isEditingObservation ? 'text-yellow-400 bg-yellow-900/20' : 'text-zinc-500 hover:text-yellow-400 hover:bg-yellow-900/10'}`}
                title="Adicionar/Editar Observação"
            >
                <StickyNote size={14} />
            </button>

            {/* Atalhos Rápidos */}
            <div className="flex bg-zinc-900 border border-zinc-800 rounded mr-2 overflow-hidden shadow-sm">
                <button onClick={() => setActiveTool('LESSON_LINK')} className="p-1.5 text-blue-500 hover:bg-blue-900/30 hover:text-blue-400" title="Vincular Aulas"><PlayCircle size={12} /></button>
                <div className="w-px bg-zinc-800"></div>

                <button onClick={handleUploadPDFClick} disabled={isUploading} className="p-1.5 text-orange-500 hover:bg-orange-900/30 hover:text-orange-400 disabled:opacity-50" title="Upload PDF">
                    {isUploading ? <span className="animate-spin text-[8px]">↻</span> : <FileText size={12} />}
                </button>
                <input type="file" ref={fileInputRef} accept="application/pdf" className="hidden" onChange={handleFileChange} />

                <div className="w-px bg-zinc-800"></div>
                <button onClick={() => setActiveTool('MAP')} className="p-1.5 text-purple-500 hover:bg-purple-900/30 hover:text-purple-400" title="Mapa Mental"><BrainCircuit size={12} /></button>
                <div className="w-px bg-zinc-800"></div>
                <button onClick={() => setActiveTool('FLASHCARD')} className="p-1.5 text-pink-500 hover:bg-pink-900/30 hover:text-pink-400" title="Flashcards"><Layers size={12} /></button>
            </div>

            <button onClick={handleAddSubtopic} className="p-1.5 text-zinc-500 hover:text-white hover:bg-zinc-800 rounded" title="Adicionar Subtópico">
                <Plus size={14} />
            </button>

            {/* BOTÃO EXCLUIR O PRÓPRIO TÓPICO */}
            <button onClick={onDelete} className="p-1.5 text-zinc-500 hover:text-red-500 hover:bg-red-900/20 rounded" title="Excluir">
                <Trash2 size={14} />
            </button>
        </div>
      </div>

      {/* ÁREA DE CONTEÚDO (EXPANDIDA) */}
      {isExpanded && (
          <div className="pl-6 pr-2 pb-2 space-y-2 animate-in slide-in-from-top-1 duration-200">

              {/* --- ÁREA DE OBSERVAÇÃO --- */}
              {isEditingObservation ? (
                  <div className="mb-4 mt-2">
                      <RichTextEditor 
                          value={observationText} 
                          onChange={setObservationText}
                          placeholder="Digite observações, dicas ou orientações para este tópico..."
                      />
                      <div className="flex gap-2 mt-2 justify-end">
                          <button onClick={handleCancelObservation} className="text-xs text-zinc-400 hover:text-white px-3 py-1.5 rounded border border-zinc-700">Cancelar</button>
                          <button onClick={handleSaveObservation} className="text-xs bg-green-600 text-white px-3 py-1.5 rounded font-bold flex items-center gap-1 hover:bg-green-500">
                              <Save size={12} /> Salvar Obs.
                          </button>
                      </div>
                  </div>
              ) : hasObservation && (
                  <div className="relative group/obs mt-2 mb-2">
                      <div 
                        className="bg-yellow-900/10 border-l-2 border-yellow-600 pl-4 py-2 pr-2 text-sm text-zinc-300 rich-content"
                        dangerouslySetInnerHTML={{ __html: topic.observation! }}
                      />
                      <style>{`
                        .rich-content ul { list-style-type: disc; padding-left: 1.5em; }
                        .rich-content ol { list-style-type: decimal; padding-left: 1.5em; }
                        .rich-content blockquote { border-left: 4px solid #ca8a04; padding-left: 1em; font-style: italic; color: #a1a1aa; }
                      `}</style>
                      <button 
                        onClick={() => setIsEditingObservation(true)}
                        className="absolute top-1 right-1 p-1 text-zinc-500 hover:text-yellow-400 opacity-0 group-hover/obs:opacity-100 transition-opacity"
                        title="Editar Observação"
                      >
                          <StickyNote size={12} />
                      </button>
                  </div>
              )}

              {/* Lista de Aulas Vinculadas */}
              {topic.linkedLessons && topic.linkedLessons.length > 0 && (
                  <div className="flex flex-wrap gap-2 pt-1">
                      {topic.linkedLessons.map(lesson => (
                          <div key={lesson.id} className="flex items-center gap-1.5 bg-blue-500/10 border border-blue-500/20 px-2 py-1 rounded text-[10px] text-blue-300 group/item hover:border-blue-500/40">
                              <PlayCircle size={10} />
                              <span className="truncate max-w-[150px]">{lesson.title}</span>
                              <button onClick={() => handleRemoveLesson(lesson.id)} className="hover:text-red-400 opacity-0 group-hover/item:opacity-100 transition-opacity ml-1"><X size={10} /></button>
                          </div>
                      ))}
                  </div>
              )}

              {/* Lista de PDFs */}
              {topic.materialPdfs && topic.materialPdfs.length > 0 && (
                  <div className="flex flex-wrap gap-2 pt-1">
                      {topic.materialPdfs.map((pdf, idx) => (
                          <div key={idx} className="flex items-center gap-1.5 bg-orange-500/10 border border-orange-500/20 px-2 py-1 rounded text-[10px] text-orange-300 group/item hover:border-orange-500/40">
                              <FileText size={10} />
                              <span className="truncate max-w-[150px]">{pdf.title}</span>
                              <button onClick={() => handleRemovePDF(pdf.url)} className="hover:text-red-400 opacity-0 group-hover/item:opacity-100 transition-opacity ml-1"><X size={10} /></button>
                          </div>
                      ))}
                  </div>
              )}

              {/* Renderização Recursiva de Subtópicos */}
              {topic.subtopics.length > 0 && (
                <div className="pt-1 flex flex-col gap-1">
                    {topic.subtopics.map((sub, index) => (
                        <AdminCourseEditalTopic 
                            key={sub.id}
                            topic={sub}
                            onUpdate={handleSubtopicUpdate}
                            // Passa a função de solicitação de exclusão do SUBTÓPICO
                            onDelete={() => handleSubtopicDeleteRequest(sub.id)}
                            depth={depth + 1}
                            courseId={courseId}
                            onMoveUp={() => handleMoveSubtopic(index, 'up')}
                            onMoveDown={() => handleMoveSubtopic(index, 'down')}
                            isFirst={index === 0}
                            isLast={index === topic.subtopics.length - 1}
                        />
                    ))}
                </div>
              )}

              {/* Mensagem de Vazio */}
              {topic.subtopics.length === 0 && lessonsCount === 0 && pdfsCount === 0 && !hasObservation && !isEditingObservation && (
                  <div className="text-[10px] text-zinc-600 italic pl-2">Nenhum conteúdo vinculado.</div>
              )}
          </div>
      )}

      {/* --- MODAIS --- */}

      <LinkLessonModal 
        isOpen={activeTool === 'LESSON_LINK'}
        onClose={() => setActiveTool(null)}
        courseId={courseId}
        onSave={handleSaveLinkedLessons}
        initialSelectedIds={topic.linkedLessons?.map(l => l.id)}
      />

      {activeTool === 'MAP' && createPortal(
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/90 backdrop-blur-sm p-6 animate-in fade-in">
            <div className="bg-zinc-950 border border-zinc-800 w-full max-w-5xl h-[85vh] rounded-2xl flex flex-col shadow-2xl overflow-hidden">
                <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-[#121418]">
                    <h3 className="text-white font-bold text-lg flex items-center gap-2"><BrainCircuit className="text-purple-500" /> Mapa Mental: {topic.name}</h3>
                    <button onClick={() => setActiveTool(null)} className="text-zinc-500 hover:text-white"><X size={24} /></button>
                </div>
                <div className="flex-1 overflow-y-auto p-6 bg-black/50 custom-scrollbar">
                    <MindMapManager nodes={topic.contentData?.mindMap || []} onChange={handleUpdateMindMap} />
                </div>
            </div>
        </div>,
        document.body
      )}

      {activeTool === 'FLASHCARD' && createPortal(
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/90 backdrop-blur-sm p-6 animate-in fade-in">
            <div className="bg-zinc-950 border border-zinc-800 w-full max-w-4xl h-[85vh] rounded-2xl flex flex-col shadow-2xl overflow-hidden">
                <div className="p-4 border-b border-zinc-800 flex justify-between items-center bg-[#121418]">
                    <h3 className="text-white font-bold text-lg flex items-center gap-2"><Layers className="text-pink-500" /> Flashcards: {topic.name}</h3>
                    <button onClick={() => setActiveTool(null)} className="text-zinc-500 hover:text-white"><X size={24} /></button>
                </div>
                <div className="flex-1 overflow-y-auto p-6 bg-black/50 custom-scrollbar">
                    <FlashcardEditor cards={topic.contentData?.flashcards || []} onChange={handleUpdateFlashcards} />
                </div>
            </div>
        </div>,
        document.body
      )}

      {/* MODAL DE CONFIRMAÇÃO DE EXCLUSÃO (SUBTÓPICO) */}
      <ConfirmationModal 
        isOpen={isDeleteModalOpen}
        onClose={() => {
            setIsDeleteModalOpen(false);
            setSubtopicToDelete(null);
        }}
        onConfirm={confirmSubtopicDelete}
        title="Excluir Subtópico?"
        message="Tem certeza que deseja excluir este subtópico? Todo o conteúdo vinculado será perdido."
        confirmText="Excluir"
        variant="danger"
        onCancel={() => {
            setIsDeleteModalOpen(false);
            setSubtopicToDelete(null);
        }}
      />

    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { 
  ChevronRight, ChevronDown, CheckCircle2, Circle, Folder, Lock, AlertTriangle, Loader2, StickyNote
} from 'lucide-react';
import { EdictTopic, EdictSubtopic, EdictStudyLevel } from '../../../services/edictService';
import { Meta, MetaType } from '../../../services/metaService';
import { useAuth } from '../../../contexts/AuthContext';
import { editalProgressService } from '../../../services/editalProgressService';
import LinkedGoalItem from './LinkedGoalItem';

interface TopicItemProps {
  item: EdictTopic | EdictSubtopic;
  depth?: number;
  completedMetaIds: Set<string>;
  activeUserMode?: boolean;
  metaLookup?: Record<string, Meta>;
  planId?: string;
  studyLevels?: EdictStudyLevel[];
  onToggleGoal?: (goal: Meta) => void;
  onBatchToggle?: (ids: string[], status: boolean) => void; // NEW PROP FOR BATCH UPDATE
  onPlayVideo?: (url: string) => void;
}

const TopicItem: React.FC<TopicItemProps> = ({ 
  item, 
  depth = 0, 
  completedMetaIds, 
  activeUserMode = false,
  metaLookup = {},
  planId,
  studyLevels,
  onToggleGoal,
  onBatchToggle,
  onPlayVideo
}) => {
  const { currentUser } = useAuth();
  const [isExpanded, setIsExpanded] = useState(false);
  const [showConfirmModal, setShowConfirmModal] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  // --- LOCAL STATE FOR OPTIMISTIC UI ---
  const [localCompletedIds, setLocalCompletedIds] = useState<Set<string>>(new Set());

  // --- STATE VERSIONING FORCED REMOUNT ---
  // Incremented to force React to destroy and recreate child components
  // ensuring they pick up the new "completed" style immediately.
  const [remountToken, setRemountToken] = useState(0);

  // Reset local state if props change (e.g. parent refresh)
  useEffect(() => {
    setLocalCompletedIds(new Set());
    setRemountToken(prev => prev + 1); // Ensure children refresh if parent data changes
  }, [completedMetaIds]);

  // Merge Prop Data + Local Optimistic Data
  const effectiveCompletedIds = useMemo(() => {
    if (localCompletedIds.size === 0) return completedMetaIds;
    const merged = new Set(completedMetaIds);
    localCompletedIds.forEach(id => merged.add(id));
    return merged;
  }, [completedMetaIds, localCompletedIds]);

  // Cast to check for children
  const topic = item as EdictTopic;
  const hasSubtopics = topic.subtopics && topic.subtopics.length > 0;

  // Cast to check for observation (needs type guard or casting as EdictTopic which has it in new definition)
  // Assuming EdictTopic interface updated in services/edictService or types file
  const observation = (item as any).observation;
  const hasObservation = !!observation && observation.trim() !== '' && observation.trim() !== '<p><br></p>';

  // Level Logic
  const levelId = (item as EdictTopic).studyLevelId;
  const levelName = levelId && studyLevels ? studyLevels.find(l => l.id === levelId)?.name : null;

  const getLevelStyle = (name: string) => {
    const norm = name?.toLowerCase() || '';
    if (norm.includes('alta') || norm.includes('muito') || norm.includes('difícil')) 
        return 'border-red-500/30 text-red-400 bg-red-500/10';
    if (norm.includes('média') || norm.includes('media') || norm.includes('médio')) 
        return 'border-yellow-500/30 text-yellow-400 bg-yellow-500/10';
    if (norm.includes('baixa') || norm.includes('fácil') || norm.includes('facil')) 
        return 'border-emerald-500/30 text-emerald-400 bg-emerald-500/10';
    return 'border-zinc-700 text-zinc-400 bg-zinc-800';
  };

  // --- PROGRESS CALCULATION & META GATHERING ---
  const { progressStats, allMetaIds } = useMemo(() => {
    let totalGoals = 0;
    let completedGoals = 0;
    const ids: string[] = [];

    const countGoals = (linkedGoals: any) => {
      if (!linkedGoals) return;
      Object.values(linkedGoals).forEach((idList: any) => {
        if (Array.isArray(idList)) {
          totalGoals += idList.length;
          idList.forEach(id => {
            ids.push(id);
            // Use EFFECTIVE IDs for calculation
            if (effectiveCompletedIds.has(id)) completedGoals++;
          });
        }
      });
    };

    // 1. Count own goals
    countGoals(item.linkedGoals);

    // 2. Recursively count subtopics goals (to show aggregate status on parent)
    const traverse = (t: EdictTopic) => {
        if (t.subtopics) {
            t.subtopics.forEach(sub => {
                countGoals(sub.linkedGoals);
            });
        }
    };
    if (hasSubtopics) traverse(topic);

    return { 
        progressStats: { total: totalGoals, completed: completedGoals },
        allMetaIds: ids
    };
  }, [item, hasSubtopics, effectiveCompletedIds]);

  const percentage = progressStats.total > 0 
    ? Math.round((progressStats.completed / progressStats.total) * 100) 
    : 0;

  const isFullyComplete = progressStats.total > 0 && progressStats.completed === progressStats.total;

  // --- HANDLERS ---

  const handleStatusClick = (e: React.MouseEvent) => {
    e.stopPropagation();

    // 1. Active User Guard
    if (!activeUserMode) {
       return; // Lock icon shows this is disabled
    }

    // 2. Logic: Only allow COMPLETING via bulk action.
    if (!isFullyComplete && allMetaIds.length > 0) {
        setShowConfirmModal(true);
    }
  };

  const confirmCompletion = async () => {
    if (!currentUser || !planId) return;
    setIsProcessing(true);
    try {
        // 1. Call Service (Persistence)
        await editalProgressService.completeTopicManually(currentUser.uid, planId, allMetaIds);

        // 2. Optimistic UI Update (Immediate Green Check)
        const newLocal = new Set(localCompletedIds);
        allMetaIds.forEach(id => newLocal.add(id));
        setLocalCompletedIds(newLocal);

        // 3. FORCE VISUAL UPDATE ON CHILDREN
        setRemountToken(prev => prev + 1);

        // 4. Trigger Batch State Update on Parent (Visual Sync Fix)
        if (onBatchToggle) {
             onBatchToggle(allMetaIds, true);
        } else if (onToggleGoal && allMetaIds.length > 0 && metaLookup && metaLookup[allMetaIds[0]]) {
             // Fallback single trigger (Deprecated but safe)
             onToggleGoal(metaLookup[allMetaIds[0]]); 
        }

        setShowConfirmModal(false);
    } catch (error) {
        console.error("Erro ao concluir em lote", error);
        alert("Erro ao salvar progresso.");
    } finally {
        setIsProcessing(false);
    }
  };

  // --- RENDER LINKED GOALS ---
  const renderLinkedGoals = () => {
    if (!item.linkedGoals) return null;

    // Flatten all linked IDs into a list of Meta objects
    const metasToRender: Meta[] = [];
    const types: MetaType[] = ['lesson', 'material', 'questions', 'law', 'summary', 'review'];

    types.forEach(type => {
        const ids = item.linkedGoals[type] || [];
        ids.forEach(id => {
            if (metaLookup[id]) {
                metasToRender.push(metaLookup[id]);
            }
        });
    });

    if (metasToRender.length === 0) return null;

    return (
        <div className="flex flex-col gap-2 mt-2 mb-2 animate-in slide-in-from-left-2 duration-300">
            {metasToRender.map(meta => {
                const isDone = effectiveCompletedIds.has(meta.id!);
                return (
                    <LinkedGoalItem 
                        // FORCE REMOUNT on status change OR manual trigger (remountToken)
                        // This guarantees the component is fresh and green instantly
                        key={`${meta.id}-v${remountToken}-${isDone ? 'done' : 'pending'}`}
                        goal={meta}
                        isCompleted={isDone}
                        activeUserMode={activeUserMode}
                        planId={planId}
                        onToggleComplete={onToggleGoal || (() => {})}
                        onPlayVideo={onPlayVideo}
                    />
                );
            })}
        </div>
    );
  };

  // --- STYLES ---
  const paddingLeft = `${depth * 1.5 + 1}rem`;
  const isTopic = depth === 0;

  return (
    <div className="flex flex-col">
      {/* HEADER ROW */}
      <div 
        className={`
          flex items-center gap-3 p-3 border-b border-zinc-800/50 transition-colors cursor-pointer select-none
          ${isExpanded ? 'bg-zinc-900/50' : 'hover:bg-zinc-900/30'}
          ${isTopic ? 'border-l-2 border-l-transparent hover:border-l-brand-red' : ''}
        `}
        style={{ paddingLeft }}
        onClick={() => setIsExpanded(!isExpanded)}
      >
        {/* Expand Icon */}
        <div className={`text-zinc-500 transition-transform duration-200 ${hasSubtopics ? '' : (progressStats.total > 0 || hasObservation ? '' : 'opacity-0')}`}>
           {isExpanded ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
        </div>

        {/* Title */}
        <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2">
                <h4 className={`text-sm font-medium truncate ${isFullyComplete ? 'text-zinc-500 line-through' : 'text-zinc-200'}`}>
                    {item.name}
                </h4>
            </div>

            {/* Progress Micro-Bar (Mobile/Desktop) */}
            {progressStats.total > 0 && (
                <div className="flex items-center gap-2 mt-1.5 w-full max-w-[200px]">
                    <div className="h-1 flex-1 bg-zinc-800 rounded-full overflow-hidden">
                        <div 
                            className={`h-full rounded-full transition-all duration-500 ${isFullyComplete ? 'bg-emerald-500' : 'bg-brand-red'}`} 
                            style={{ width: `${percentage}%` }}
                        />
                    </div>
                    <span className={`text-[9px] font-bold ${isFullyComplete ? 'text-emerald-500' : 'text-zinc-500'}`}>
                        {percentage}%
                    </span>
                </div>
            )}
        </div>

        {/* Observation Badge (Collapsed) */}
        {!isExpanded && hasObservation && (
            <div className="mr-2 text-yellow-500/50 flex items-center gap-1" title="Possui observação">
                <StickyNote size={12} />
            </div>
        )}

        {/* Level Badge (Aligned Right, Before Status) */}
        {levelName && (
            <span className={`text-[9px] font-bold uppercase px-2 py-0.5 rounded border tracking-wider shrink-0 ${getLevelStyle(levelName)}`}>
                {levelName}
            </span>
        )}

        {/* Status Icon */}
        <button
            onClick={handleStatusClick}
            disabled={!activeUserMode || isFullyComplete} // Disable if mode off OR already done
            className={`shrink-0 transition-colors ${!activeUserMode ? 'cursor-not-allowed' : (isFullyComplete ? 'cursor-default' : 'cursor-pointer hover:scale-110')}`}
            title={!activeUserMode ? "Modo Automático (Conclusão Manual Bloqueada)" : (isFullyComplete ? "Tópico Concluído" : "Marcar Tópico como Concluído")}
        >
            {isFullyComplete ? (
                <CheckCircle2 size={18} className="text-emerald-500" />
            ) : !activeUserMode ? (
                <Lock size={16} className="text-zinc-700" />
            ) : (
                <Circle size={18} className="text-zinc-600 hover:text-zinc-400" />
            )}
        </button>
      </div>

      {/* BODY (Subtopics + Linked Goals + Observation) */}
      {isExpanded && (
        <div className="animate-in slide-in-from-top-1 duration-200">

            {/* 1. Observation Block (NEW) */}
            {hasObservation && (
                <div 
                    className="mb-2 mt-2 mr-2 p-3 bg-yellow-900/10 border-l-2 border-yellow-600 text-sm text-zinc-300 rich-content"
                    style={{ marginLeft: `${(depth + 1) * 1.5 + 0.5}rem` }}
                >
                    <div className="flex items-center gap-2 text-yellow-500 mb-1 text-[10px] font-bold uppercase tracking-widest">
                        <StickyNote size={12} /> Observação
                    </div>
                    <div 
                        dangerouslySetInnerHTML={{ __html: observation }} 
                        className="prose prose-invert prose-sm max-w-none text-zinc-400 text-xs"
                    />
                    <style>{`
                        .rich-content ul { list-style-type: disc; padding-left: 1.5em; }
                        .rich-content ol { list-style-type: decimal; padding-left: 1.5em; }
                    `}</style>
                </div>
            )}

            {/* 2. Goals attached to THIS item */}
            {renderLinkedGoals()}

            {/* 3. Subtopics Recursive Render */}
            {hasSubtopics && topic.subtopics.map(sub => (
                <TopicItem 
                    key={sub.id} 
                    item={sub} 
                    depth={depth + 1} 
                    // Pass EFFECTIVE IDs down to children to maintain visual state
                    completedMetaIds={effectiveCompletedIds}
                    activeUserMode={activeUserMode}
                    metaLookup={metaLookup}
                    planId={planId}
                    studyLevels={studyLevels}
                    onToggleGoal={onToggleGoal}
                    onBatchToggle={onBatchToggle} // PROPAGATE BATCH TOGGLE DOWN
                    onPlayVideo={onPlayVideo}
                />
            ))}

            {/* 4. Empty State Check */}
            {progressStats.total === 0 && !hasSubtopics && !hasObservation && (
                <div 
                    className="py-3 pr-4 border-b border-zinc-800/30 bg-zinc-950/30 text-zinc-600 text-xs italic"
                    style={{ paddingLeft: `${(depth + 1) * 1.5 + 2.5}rem` }}
                >
                    Sem conteúdo vinculado.
                </div>
            )}
        </div>
      )}

      {/* MODAL DE CONFIRMAÇÃO DE CONCLUSÃO DO TÓPICO */}
      {showConfirmModal && createPortal(
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200" onClick={() => setShowConfirmModal(false)}>
            <div 
                className="bg-zinc-900 border border-zinc-800 p-6 rounded-xl w-full max-w-sm shadow-2xl animate-in zoom-in-95 duration-200"
                onClick={e => e.stopPropagation()}
            >
                <div className="flex flex-col items-center text-center gap-4">
                    <div className="p-3 rounded-full bg-emerald-500/10 text-emerald-500 border border-emerald-500/20 shadow-[0_0_15px_rgba(16,185,129,0.2)]">
                        <CheckCircle2 size={32} />
                    </div>

                    <h3 className="text-lg font-black text-white uppercase tracking-tighter">
                        Concluir Tópico?
                    </h3>

                    <div className="text-sm text-zinc-400 leading-relaxed">
                        <p>Você está prestes a marcar <strong>todas as {progressStats.total} metas</strong> deste tópico como concluídas.</p>
                        <p className="mt-2 text-xs bg-zinc-950 p-2 rounded border border-zinc-800 text-zinc-500">
                            Isso removerá quaisquer agendamentos futuros dessas metas do seu calendário.
                        </p>
                    </div>

                    <div className="flex gap-3 w-full mt-2">
                        <button 
                            onClick={() => setShowConfirmModal(false)}
                            disabled={isProcessing}
                            className="flex-1 py-3 rounded-lg border border-zinc-700 hover:bg-zinc-800 text-zinc-300 font-bold uppercase text-xs tracking-widest transition-colors"
                        >
                            Cancelar
                        </button>
                        <button 
                            onClick={confirmCompletion}
                            disabled={isProcessing}
                            className="flex-1 py-3 rounded-lg bg-emerald-600 hover:bg-emerald-500 text-white font-black uppercase text-xs tracking-widest transition-all shadow-lg shadow-emerald-900/20 flex items-center justify-center gap-2"
                        >
                            {isProcessing ? <Loader2 size={14} className="animate-spin" /> : 'Confirmar'}
                        </button>
                    </div>
                </div>
            </div>
        </div>,
        document.body
      )}
    </div>
  );
};

export default TopicItem;

