import React, { useState, useEffect } from 'react';
import { 
  BookOpen, ChevronDown, ChevronRight, FileText, 
  PlayCircle, Layers, BrainCircuit, StickyNote, Loader2 
} from 'lucide-react';
import { courseService } from '../../../../services/courseService';
import { CourseEditalStructure, CourseEditalDiscipline, CourseEditalTopic } from '../../../../types/courseEdital';

interface StudentCourseEditalProps {
  courseId: string;
}

export const StudentCourseEdital: React.FC<StudentCourseEditalProps> = ({ courseId }) => {
  const [structure, setStructure] = useState<CourseEditalStructure | null>(null);
  const [loading, setLoading] = useState(true);
  const [expandedDisciplines, setExpandedDisciplines] = useState<Record<string, boolean>>({});
  const [expandedTopics, setExpandedTopics] = useState<Record<string, boolean>>({});

  useEffect(() => {
    const loadEdital = async () => {
      setLoading(true);
      try {
        const data = await courseService.getCourseEdital(courseId);
        setStructure(data);

        // Optionally auto-expand if there are few disciplines
        if (data && data.disciplines.length <= 2) {
            const initialExpanded: Record<string, boolean> = {};
            data.disciplines.forEach(d => initialExpanded[d.id] = true);
            setExpandedDisciplines(initialExpanded);
        }
      } catch (error) {
        console.error("Erro ao carregar edital:", error);
      } finally {
        setLoading(false);
      }
    };
    loadEdital();
  }, [courseId]);

  const toggleDiscipline = (id: string) => {
    setExpandedDisciplines(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const toggleTopic = (id: string) => {
    setExpandedTopics(prev => ({ ...prev, [id]: !prev[id] }));
  };

  if (loading) {
    return (
      <div className="flex justify-center py-20">
        <Loader2 className="animate-spin text-red-600" size={32} />
      </div>
    );
  }

  if (!structure || !structure.disciplines || structure.disciplines.length === 0) {
    return (
      <div className="text-center py-20 border border-dashed border-gray-800 rounded-xl bg-zinc-900/20">
        <BookOpen className="mx-auto text-zinc-600 mb-3" size={40} />
        <p className="text-zinc-500 font-bold uppercase text-sm">Edital Verticalizado indisponível.</p>
        <p className="text-zinc-600 text-xs mt-1">Este curso ainda não possui um edital configurado.</p>
      </div>
    );
  }

  return (
    <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {structure.disciplines.map((discipline) => (
        <div 
          key={discipline.id} 
          className="border border-zinc-800 rounded-xl bg-[#121418] overflow-hidden"
        >
          {/* Discipline Header */}
          <div 
            onClick={() => toggleDiscipline(discipline.id)}
            className="p-4 flex items-center justify-between cursor-pointer hover:bg-zinc-900/50 transition-colors select-none"
          >
            <div className="flex items-center gap-3">
              <div className={`p-2 rounded-lg bg-red-900/20 text-red-500`}>
                <BookOpen size={18} />
              </div>
              <h3 className="text-white font-bold uppercase text-sm">{discipline.name}</h3>
              <span className="text-[10px] text-zinc-500 bg-black/40 px-2 py-0.5 rounded border border-zinc-800">
                {discipline.topics.length} Tópicos
              </span>
            </div>
            <div className={`text-zinc-500 transition-transform duration-200 ${expandedDisciplines[discipline.id] ? 'rotate-180' : ''}`}>
              <ChevronDown size={18} />
            </div>
          </div>

          {/* Discipline Body (Topics) */}
          {expandedDisciplines[discipline.id] && (
            <div className="border-t border-zinc-800 bg-black/20 p-2">
              {discipline.topics.length === 0 && (
                 <div className="p-4 text-center text-zinc-600 text-xs italic">Nenhum tópico cadastrado.</div>
              )}
              {discipline.topics.map((topic) => (
                <StudentTopicItem 
                  key={topic.id} 
                  topic={topic} 
