        </div>
      ))}
    </div>
  );
};

// --- SUB-COMPONENTE: TÓPICO (Recursivo para Subtópicos) ---
const StudentTopicItem: React.FC<{ 
  topic: CourseEditalTopic; 
  isExpanded: boolean; 
  onToggle: () => void; 
  depth?: number 
}> = ({ topic, isExpanded, onToggle, depth = 0 }) => {

  const hasContent = 
    (topic.linkedLessons && topic.linkedLessons.length > 0) || 
    (topic.materialPdfs && topic.materialPdfs.length > 0) ||
    (topic.observation && topic.observation.trim() !== '');

  const hasSubtopics = topic.subtopics && topic.subtopics.length > 0;
  const isLeaf = !hasSubtopics;

  const handleHeaderClick = (e: React.MouseEvent) => {
    // Se tiver conteúdo ou subtópicos, permite expandir
    if (hasContent || hasSubtopics) {
      onToggle();
