          <div className="text-zinc-500 shrink-0">
             {(hasContent || hasSubtopics) ? (
                 isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />
             ) : (
                 <div className="w-1.5 h-1.5 rounded-full bg-zinc-700 ml-1.5"></div>
             )}
          </div>

          <span className={`text-xs font-medium uppercase truncate ${isExpanded ? 'text-white' : 'text-zinc-400'}`}>
            {topic.name}
          </span>

          {/* Badges de Conteúdo */}
          <div className="flex items-center gap-1 ml-2">
            {(topic.linkedLessons?.length || 0) > 0 && <span className="text-[9px] text-blue-500 bg-blue-900/10 px-1.5 rounded border border-blue-900/20 flex items-center gap-0.5"><PlayCircle size={8} /> {topic.linkedLessons?.length}</span>}
            {(topic.materialPdfs?.length || 0) > 0 && <span className="text-[9px] text-orange-500 bg-orange-900/10 px-1.5 rounded border border-orange-900/20 flex items-center gap-0.5"><FileText size={8} /> {topic.materialPdfs?.length}</span>}
            {topic.observation && <span className="text-[9px] text-yellow-500 bg-yellow-900/10 px-1.5 rounded border border-yellow-900/20 flex items-center gap-0.5"><StickyNote size={8} /> Obs</span>}
          </div>
