           {/* Observação */}
           {topic.observation && (
             <div className="bg-yellow-900/10 border-l-2 border-yellow-600 pl-3 py-2 pr-2 text-xs text-zinc-400">
                <div dangerouslySetInnerHTML={{ __html: topic.observation }} className="prose prose-invert prose-sm max-w-none" />
             </div>
           )}

           {/* Aulas Vinculadas */}
           {topic.linkedLessons && topic.linkedLessons.length > 0 && (
             <div className="flex flex-wrap gap-2">
               {topic.linkedLessons.map((lesson) => (
                 <div key={lesson.id} className="flex items-center gap-2 px-3 py-1.5 rounded-md bg-blue-950/30 border border-blue-900/30 text-blue-400 text-xs">
                    <PlayCircle size={12} />
                    <span className="uppercase font-bold text-[10px]">{lesson.title}</span>
                 </div>
               ))}
             </div>
           )}

           {/* PDFs */}
           {topic.materialPdfs && topic.materialPdfs.length > 0 && (
             <div className="flex flex-wrap gap-2">
               {topic.materialPdfs.map((pdf, idx) => (
                 <a 
                    key={idx} 
                    href={pdf.url} 
