                              key={module.id} 
                              module={module} 
                              onClick={setSelectedModule} 
                          />
                      ))}
                  </div>
              )
          ) : (
              // VISÃO DO EDITAL VERTICALIZADO
              <StudentCourseEdital courseId={course.id} />
          )}
      </div>
    </div>
  );
}

