import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { courseService } from '../../../../services/courseService';
import { ChevronRight, PlayCircle, FileText, Network, Layers, BookOpen, X } from 'lucide-react';
import { useAuth } from '../../../../contexts/AuthContext';
// Importações das interações
import { openWatermarkedPdf } from '../../../../utils/pdfSecurityService';
import { CoursePlayerContent } from '../player/CoursePlayerContent';

export function StudentCourseEdital({ courseId }: { courseId: string }) {
  const [editalData, setEditalData] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadEdital = async () => {
      setLoading(true);
      try {
        const data = await courseService.getCourseEdital(courseId);
        setEditalData(data);
      } catch (error) {
        console.error("Erro ao carregar edital:", error);
      } finally {
        setLoading(false);
      }
    };
    loadEdital();
  }, [courseId]);

  if (loading) return <div className="animate-pulse h-40 bg-gray-900 rounded-xl"></div>;
  if (!editalData || !editalData.disciplines || editalData.disciplines.length === 0) {
      return <div className="text-gray-500 italic p-6 bg-[#121418] border border-gray-800 rounded-xl text-center">Nenhum edital cadastrado para este curso.</div>;
  }

  return (
    <div className="space-y-4">
      {editalData.disciplines.map((discipline: any) => (
        <StudentDisciplineAccordion key={discipline.id} discipline={discipline} />
      ))}
    </div>
  );
}

