export function StudentCourseEdital({ courseId }: { courseId: string }) {
  const [editalData, setEditalData] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadEdital = async () => {
      setLoading(true);
      try {
        const data = await courseService.getCourseEdital(courseId);
        setEditalData(data);
      } catch (error) {
        console.error("Erro ao carregar edital:", error);
      } finally {
        setLoading(false);
      }
    };
    loadEdital();
  }, [courseId]);

  if (loading) return <div className="animate-pulse h-40 bg-gray-900 rounded-xl"></div>;
  if (!editalData || !editalData.disciplines || editalData.disciplines.length === 0) {
      return <div className="text-gray-500 italic p-6 bg-[#121418] border border-gray-800 rounded-xl text-center">Nenhum edital cadastrado para este curso.</div>;
  }

  return (
    <div className="space-y-4">
      {editalData.disciplines.map((discipline: any) => (
        <StudentDisciplineAccordion key={discipline.id} discipline={discipline} />
      ))}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { courseService } from '../../../../services/courseService';
import { ChevronRight, PlayCircle, FileText, Network, Layers, BookOpen, X } from 'lucide-react';
import { useAuth } from '../../../../contexts/AuthContext';
// Importações das interações
import { openWatermarkedPdf } from '../../../../utils/pdfSecurityService';
import { CoursePlayerContent } from '../player/CoursePlayerContent';

// ==========================================
// 2. ACORDEÃO DO TÓPICO E CONTEÚDOS VINCULADOS
// ==========================================
const StudentTopicAccordion: React.FC<{ topic: any }> = ({ topic }) => {
  const [isOpen, setIsOpen] = useState(false);
  const { currentUser: user, userData } = useAuth(); 

  // Estados para gerenciar as aberturas de tela
  const [activeLesson, setActiveLesson] = useState<any | null>(null);
  const [openingPdfId, setOpeningPdfId] = useState<string | null>(null);
  const [isViewingMindMap, setIsViewingMindMap] = useState(false);
  const [isViewingFlashcards, setIsViewingFlashcards] = useState(false);

  // --- HANDLER DE PDF COM MARCA D'ÁGUA ---
  const handleOpenPdf = async (url: string, id: string) => {
    if (!user || openingPdfId) return;
    setOpeningPdfId(id);
    try {
        await openWatermarkedPdf(url, {
            email: user.email || 'Email não identificado',
            cpf: userData?.cpf || user.uid // Usa CPF do perfil ou UID como fallback
        });
    } catch (error) {
        console.error("Erro ao gerar PDF seguro:", error);
        alert("Não foi possível gerar o documento seguro. Tente novamente.");
    } finally {
        setOpeningPdfId(null);
    }
  };

  return (
    <>
      {/* COMPONENTE PRINCIPAL DO TÓPICO */}
      <div className="bg-[#121418] border border-gray-800 rounded-lg overflow-hidden">
        <div 
          onClick={() => setIsOpen(!isOpen)}
          className="flex items-center justify-between p-3 hover:bg-[#1a1d24] transition-colors cursor-pointer select-none group"
        >
          <div className="flex items-center gap-2">
            <ChevronRight size={14} className={`text-gray-500 transition-transform ${isOpen ? 'rotate-90' : 'group-hover:text-white'}`} />
            <h4 className="text-gray-200 font-bold text-xs uppercase">{topic.name}</h4>
          </div>
        </div>

        {isOpen && (
          <div className="p-4 border-t border-gray-800/50 bg-black flex flex-col gap-4">

            {/* OBSERVAÇÃO DO ADMINISTRADOR */}
            {topic.observation && (
              <div className="p-4 bg-yellow-500/5 border border-yellow-500/20 rounded-xl">
                  <span className="text-[10px] font-bold text-yellow-500 uppercase tracking-wider block mb-2">Aviso / Observação</span>
                  <div className="prose prose-invert prose-sm max-w-none text-gray-300" dangerouslySetInnerHTML={{ __html: topic.observation }} />
              </div>
            )}

            {/* LISTA DE CONTEÚDOS VINCULADOS */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">

              {/* AULAS VINCULADAS */}
              {topic.linkedLessons?.map((lesson: any) => (
                  <button key={lesson.id} onClick={() => setActiveLesson(lesson)} className="flex items-center gap-3 p-3 bg-[#1a1d24] border border-gray-800 rounded-lg hover:border-red-600/50 transition-colors text-left group">
                      <div className="w-8 h-8 rounded-full bg-red-900/20 text-red-500 flex items-center justify-center group-hover:scale-110 transition-transform">
                          <PlayCircle size={16} />
                      </div>
                      <div className="flex-1 min-w-0">
                          <span className="text-[9px] text-gray-500 font-bold uppercase block mb-0.5">Assistir Aula</span>
                          <span className="text-xs text-white font-bold block truncate">{lesson.title}</span>
                      </div>
                  </button>
              ))}

              {/* PDFs VINCULADOS */}
              {topic.materialPdfs?.map((pdf: any, idx: number) => {
                  const pdfId = pdf.id || `pdf-${idx}`;
                  return (
                    <button key={pdfId} onClick={() => handleOpenPdf(pdf.url, pdfId)} className={`flex items-center gap-3 p-3 bg-[#1a1d24] border border-gray-800 rounded-lg transition-colors text-left group ${openingPdfId === pdfId ? 'opacity-70 cursor-not-allowed' : 'hover:border-blue-600/50'}`}>
                        <div className="w-8 h-8 rounded-full bg-blue-900/20 text-blue-500 flex items-center justify-center group-hover:scale-110 transition-transform">
                            {openingPdfId === pdfId ? (
                                <div className="animate-spin rounded-full h-4 w-4 border-2 border-blue-500 border-t-transparent rounded-full"></div>
                            ) : (
                                <FileText size={16} />
                            )}
                        </div>
                        <div className="flex-1 min-w-0">
                            <span className="text-[9px] text-gray-500 font-bold uppercase block mb-0.5">
                                {openingPdfId === pdfId ? <span className="text-blue-400 animate-pulse">Gerando Seguro...</span> : "Material em PDF"}
                            </span>
                            <span className="text-xs text-white font-bold block truncate">{pdf.title || `Material ${idx + 1}`}</span>
                        </div>
                    </button>
                  );
              })}

              {/* MAPAS MENTAIS */}
              {topic.mindMap && (
                  <div className="col-span-1 md:col-span-2 flex items-center justify-between p-3 bg-[#1a1d24] border border-gray-800 rounded-lg">
                      <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-full bg-purple-900/20 text-purple-500 flex items-center justify-center">
                              <Network size={16} />
                          </div>
                          <div>
                              <span className="text-[9px] text-gray-500 font-bold uppercase block mb-0.5">Ferramenta de Resumo</span>
                              <span className="text-xs text-white font-bold block">Mapa Mental do Professor</span>
                          </div>
                      </div>
                      <div className="flex gap-2">
                          <button onClick={() => setIsViewingMindMap(true)} className="px-4 py-2 bg-purple-600 hover:bg-purple-500 text-white text-[10px] font-bold uppercase rounded transition-colors">Visualizar</button>
                          {/* Botão de Criação (Futuro) */}
                          <button onClick={() => alert('Em breve: Criação de Mapas Mentais do Aluno')} className="px-4 py-2 bg-black border border-gray-700 hover:border-gray-500 text-gray-300 text-[10px] font-bold uppercase rounded transition-colors hidden sm:block">Criar o Meu</button>
                      </div>
                  </div>
              )}

              {/* FLASHCARDS */}
              {topic.flashcards && (
                  <div className="col-span-1 md:col-span-2 flex items-center justify-between p-3 bg-[#1a1d24] border border-gray-800 rounded-lg">
                      <div className="flex items-center gap-3">
                          <div className="w-8 h-8 rounded-full bg-emerald-900/20 text-emerald-500 flex items-center justify-center">
                              <Layers size={16} />
                          </div>
                          <div>
                              <span className="text-[9px] text-gray-500 font-bold uppercase block mb-0.5">Ferramenta de Revisão</span>
                              <span className="text-xs text-white font-bold block">Cards de Revisão</span>
                          </div>
                      </div>
                      <div className="flex gap-2">
                          <button onClick={() => setIsViewingFlashcards(true)} className="px-4 py-2 bg-emerald-600 hover:bg-emerald-500 text-white text-[10px] font-bold uppercase rounded transition-colors">Praticar</button>
                          {/* Botão de Criação (Futuro) */}
                          <button onClick={() => alert('Em breve: Criação de Flashcards do Aluno')} className="px-4 py-2 bg-black border border-gray-700 hover:border-gray-500 text-gray-300 text-[10px] font-bold uppercase rounded transition-colors hidden sm:block">Criar Cards</button>
                      </div>
                  </div>
              )}

            </div>

            {/* SUBTÓPICOS RECURSIVOS */}
            {topic.subtopics && topic.subtopics.length > 0 && (
              <div className="mt-4 space-y-2 border-l border-gray-800 pl-3">
                  {topic.subtopics.map((sub: any) => (
                    <StudentTopicAccordion key={sub.id} topic={sub} />
                  ))}
              </div>
            )}

          </div>
        )}
      </div>

      {/* ==================================================== */}
      {/* MODAIS SOBREPOSTOS (OVERLAYS DE TELA CHEIA)            */}
      {/* ==================================================== */}

      {/* MODAL 1: PLAYER DE VÍDEO (AULA) */}
      {activeLesson && (
        <div className="fixed inset-0 z-[100] bg-black flex flex-col animate-in fade-in">
            {/* Header do Player */}
            <div className="h-14 border-b border-gray-800 flex items-center justify-between px-4 shrink-0 bg-[#0f1114]">
                <div className="flex items-center gap-4">
                  <button onClick={() => setActiveLesson(null)} className="flex items-center gap-2 text-gray-400 hover:text-white uppercase font-bold text-xs transition-colors">
                      <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
                      <span className="hidden sm:inline">Voltar ao Edital</span>
                  </button>
                  <div className="w-px h-4 bg-gray-800"></div>
                  <h2 className="text-white font-bold text-xs uppercase flex items-center gap-2">
                    <PlayCircle size={14} className="text-red-500" />
                    {activeLesson.title}
                  </h2>
                </div>
                <button onClick={() => setActiveLesson(null)} className="p-2 text-gray-400 hover:text-white rounded-full hover:bg-white/5">
                    <X size={20} />
                </button>
            </div>
            {/* Conteúdo do Player (Reutilizando o componente existente) */}
            <div className="flex-1 overflow-y-auto bg-black">
                {/* Repassamos a aula clicada para o CoursePlayerContent puxar o vídeo do banco */}
                <CoursePlayerContent lesson={activeLesson} /> 
            </div>
        </div>
      )}

      {/* MODAL 2: MAPA MENTAL (Placeholder de Visualização) */}
      {isViewingMindMap && (
        <div className="fixed inset-0 z-[100] bg-[#0f1114] flex flex-col animate-in fade-in">
           <div className="h-14 border-b border-gray-800 flex items-center justify-between px-4 shrink-0 bg-black">
                <h2 className="text-white font-bold text-xs uppercase flex items-center gap-2">
                  <Network size={14} className="text-purple-500" />
                  Mapa Mental do Professor
                </h2>
                <button onClick={() => setIsViewingMindMap(false)} className="p-2 text-gray-400 hover:text-white flex items-center gap-2 text-xs font-bold uppercase">
                    Fechar <X size={16} />
                </button>
           </div>
           <div className="flex-1 flex items-center justify-center">
              {/* No futuro, plugaremos o <MindMapFullscreen readOnly={true} /> aqui */}
              <p className="text-gray-500 text-sm">Visualizador de Mapa Mental em Construção</p>
           </div>
        </div>
      )}

      {/* MODAL 3: FLASHCARDS (Placeholder de Visualização) */}
      {isViewingFlashcards && (
        <div className="fixed inset-0 z-[100] bg-[#0f1114] flex flex-col animate-in fade-in">
           <div className="h-14 border-b border-gray-800 flex items-center justify-between px-4 shrink-0 bg-black">
                <h2 className="text-white font-bold text-xs uppercase flex items-center gap-2">
                  <Layers size={14} className="text-emerald-500" />
                  Cards de Revisão
                </h2>
                <button onClick={() => setIsViewingFlashcards(false)} className="p-2 text-gray-400 hover:text-white flex items-center gap-2 text-xs font-bold uppercase">
                    Fechar <X size={16} />
                </button>
           </div>
           <div className="flex-1 flex items-center justify-center">
              {/* No futuro, plugaremos o sistema de estudo de Flashcards aqui */}
              <p className="text-gray-500 text-sm">Visualizador de Flashcards em Construção</p>
           </div>
        </div>
      )}

    </>
  );
};

